window.BILARA = window.BILARA || {};
window.BILARA["dn33"] = window.BILARA["dn33"] || {};
window.BILARA["dn33"]["vi"] = {
  "dn33:0.1": "Trường Bộ Kinh 33",
  "dn33:0.2": "Kinh Tụng Đọc",
  "dn33:1.1.1": "Tôi nghe như vầy—",
  "dn33:1.1.2": "Một thời, Thế Tôn đi du hành trong xứ Mallā cùng với đại chúng tỳ kheo gồm khoảng năm trăm vị, và đã đến thành Pāvā của dân Mallā.",
  "dn33:1.1.3": "Tại đó, Thế Tôn ở tại vườn xoài của Cunda, con người thợ rèn, ở Pāvā.",
  "dn33:1.2.1": "Lúc bấy giờ, dân Mallā ở Pāvā có một hội trường mới tên là Ubbhataka, vừa mới làm xong, chưa từng có sa môn, bà la môn hay bất cứ người nào ở trong đó trước đó.",
  "dn33:1.2.2": "Dân Mallā ở Pāvā nghe rằng: “Nghe nói Thế Tôn đang du hành trong xứ Mallā cùng với đại chúng tỳ kheo gồm khoảng năm trăm vị, nay đã đến Pāvā và đang ở tại vườn xoài của Cunda, con người thợ rèn.”",
  "dn33:1.2.3": "Bấy giờ, dân Mallā ở Pāvā đi đến chỗ Thế Tôn; đến nơi, họ đảnh lễ Thế Tôn rồi ngồi xuống một bên. Khi đã ngồi xuống một bên, dân Mallā ở Pāvā bạch Thế Tôn:",
  "dn33:1.2.4": "“Bạch Thế Tôn, ở đây dân Mallā ở Pāvā có một hội trường mới tên là Ubbhataka, vừa mới làm xong, chưa từng có sa môn, bà la môn hay bất cứ người nào ở trong đó trước đó.",
  "dn33:1.2.5": "Kính mong Thế Tôn dùng hội trường ấy trước tiên; sau khi Thế Tôn đã dùng trước rồi, dân Mallā ở Pāvā sẽ dùng sau.",
  "dn33:1.2.6": "Điều ấy sẽ đem lại lợi ích và an vui lâu dài cho dân Mallā ở Pāvā.”",
  "dn33:1.2.7": "Thế Tôn im lặng nhận lời.",
  "dn33:1.3.1": "Bấy giờ, dân Mallā ở Pāvā biết Thế Tôn đã nhận lời, liền từ chỗ ngồi đứng dậy, đảnh lễ Thế Tôn, đi nhiễu bên phải rồi đến hội trường; đến nơi, họ trải khắp hội trường, sắp đặt chỗ ngồi cho Thế Tôn, đặt bình nước, thắp đèn dầu rồi đi đến chỗ Thế Tôn;",
  "dn33:1.3.2": "đến nơi, họ đảnh lễ Thế Tôn rồi đứng sang một bên.",
  "dn33:1.3.3": "Khi đã đứng sang một bên, dân Mallā ở Pāvā bạch Thế Tôn:",
  "dn33:1.3.4": "“Bạch Thế Tôn, hội trường đã được trải xong, chỗ ngồi cho Thế Tôn đã được sắp đặt, bình nước đã được đặt, đèn dầu đã được thắp.",
  "dn33:1.3.5": "Bây giờ, bạch Thế Tôn, nếu Thế Tôn thấy đã đến lúc.”",
  "dn33:1.4.1": "Bấy giờ, Thế Tôn đắp y, cầm bát và y, cùng với chúng tỳ kheo đi đến hội trường; đến nơi, Ngài rửa chân, bước vào hội trường, ngồi dựa cột giữa, mặt hướng về phía đông.",
  "dn33:1.4.2": "Chúng tỳ kheo cũng rửa chân, bước vào hội trường, ngồi dựa vách phía tây, mặt hướng về phía đông, lấy Thế Tôn làm chỗ hướng đến.",
  "dn33:1.4.3": "Dân Mallā ở Pāvā cũng rửa chân, bước vào hội trường, ngồi dựa vách phía đông, mặt hướng về phía tây, lấy Thế Tôn làm chỗ hướng đến.",
  "dn33:1.4.4": "Bấy giờ, Thế Tôn dùng lời pháp chỉ dạy, khích lệ, làm phấn chấn và làm hoan hỷ dân Mallā ở Pāvā suốt phần lớn đêm, rồi cho họ ra về:",
  "dn33:1.4.5": "“Đêm đã khuya rồi, này Vāseṭṭha.",
  "dn33:1.4.6": "Bây giờ các ông hãy làm điều các ông thấy là hợp lúc.”",
  "dn33:1.4.7": "“Vâng, bạch Thế Tôn,” dân Mallā ở Pāvā đáp lời Thế Tôn, rồi từ chỗ ngồi đứng dậy, đảnh lễ Thế Tôn, đi nhiễu bên phải và ra về.",
  "dn33:1.5.1": "Bấy giờ, khi dân Mallā ở Pāvā vừa ra về không bao lâu, Thế Tôn nhìn khắp chúng tỳ kheo đang yên lặng, rồi gọi tôn giả Sāriputta:",
  "dn33:1.5.2": "“Này Sāriputta, chúng tỳ kheo không còn hôn trầm buồn ngủ.",
  "dn33:1.5.3": "Này Sāriputta, hãy thuyết pháp cho các tỳ kheo.",
  "dn33:1.5.4": "Lưng ta mỏi rồi.",
  "dn33:1.5.5": "Ta sẽ nằm nghỉ.”",
  "dn33:1.5.6": "“Vâng, bạch Thế Tôn,” tôn giả Sāriputta vâng đáp Thế Tôn.",
  "dn33:1.5.7": "Bấy giờ, Thế Tôn gấp tấm y tăng già lê làm bốn, trải ra rồi nằm theo thế sư tử nghiêng hông bên phải, chân này đặt lên chân kia, tỉnh giác sáng suốt, ghi nhớ ý định sẽ thức dậy.",
  "dn33:1.6.1": "Lúc bấy giờ, Nigaṇṭha Nāṭaputta vừa mới qua đời tại Pāvā.",
  "dn33:1.6.2": "Sau khi ông ta qua đời, các Nigaṇṭha bị chia rẽ, thành hai phe, sinh ra cãi cọ, sinh ra tranh chấp, rơi vào tranh luận, dùng lời lẽ như giáo mác đâm chọc lẫn nhau:",
  "dn33:1.6.3": "“Anh không hiểu pháp và luật này, tôi hiểu pháp và luật này; làm sao anh có thể hiểu pháp và luật này được? Anh thực hành sai, tôi thực hành đúng. Điều tôi nói là hợp, điều anh nói là không hợp. Điều đáng nói trước thì anh lại nói sau, điều đáng nói sau thì anh lại nói trước. Điều anh suy tính kỹ rồi lại bị đảo ngược. Lập luận của anh đã bị bác bỏ, anh đã bị đánh bại. Hãy đi mà gỡ lấy lời nói của mình, hoặc hãy tự tháo gỡ nếu anh làm nổi.”",
  "dn33:1.6.4": "Dường như giữa các Nigaṇṭha, đệ tử của Nāṭaputta, chỉ toàn là cảnh chém giết nhau.",
  "dn33:1.6.5": "Ngay cả những đệ tử tại gia của Nigaṇṭha Nāṭaputta, mặc áo trắng, cũng chán ngán, nguội lạnh, quay lưng với các Nigaṇṭha, đệ tử của Nāṭaputta, vì pháp và luật ấy được giảng không khéo, trình bày không rõ, không đưa đến giải thoát, không dẫn đến lắng dịu, không phải do bậc Giác ngộ chân chánh tuyên thuyết, đã bị chia rẽ, không còn chỗ nương tựa.",
  "dn33:1.7.1": "Bấy giờ, tôn giả Sāriputta gọi các tỳ kheo:",
  "dn33:1.7.2": "“Này các hiền giả, Nigaṇṭha Nāṭaputta vừa mới qua đời tại Pāvā,",
  "dn33:1.7.3": "sau khi ông ta qua đời, các Nigaṇṭha bị chia rẽ, thành hai phe … đã bị chia rẽ, không còn chỗ nương tựa.",
  "dn33:1.7.4": "Này các hiền giả, đúng là như vậy đối với một pháp và luật được giảng không khéo, trình bày không rõ, không đưa đến giải thoát, không dẫn đến lắng dịu, không phải do bậc Giác ngộ chân chánh tuyên thuyết.",
  "dn33:1.7.5": "Còn pháp của chúng ta do Thế Tôn khéo giảng, khéo trình bày, đưa đến giải thoát, dẫn đến lắng dịu, do bậc Giác ngộ chân chánh tuyên thuyết.",
  "dn33:1.7.6": "Ở đây, tất cả chúng ta nên cùng nhau tụng đọc, không nên tranh cãi, để đời sống phạm hạnh này được lâu bền, tồn tại dài lâu, vì lợi ích cho nhiều người, vì an vui cho nhiều người, vì thương đời, vì lợi ích, vì an vui cho chư thiên và loài người.",
  "dn33:1.7.7": "Này các hiền giả, pháp nào do Thế Tôn của chúng ta khéo giảng, khéo trình bày, đưa đến giải thoát, dẫn đến lắng dịu, do bậc Giác ngộ chân chánh tuyên thuyết;",
  "dn33:1.7.8": "ở đó tất cả chúng ta nên cùng nhau tụng đọc, không nên tranh cãi, để đời sống phạm hạnh này được lâu bền, tồn tại dài lâu, vì lợi ích cho nhiều người, vì an vui cho nhiều người, vì thương đời, vì lợi ích, vì an vui cho chư thiên và loài người?",
  "dn33:1.7.9.0": "1. Một pháp",
  "dn33:1.7.10": "Này các hiền giả, có một pháp do Thế Tôn ấy, bậc biết, bậc thấy, bậc A-la-hán, bậc Giác ngộ chân chánh, khéo giảng dạy.",
  "dn33:1.7.11": "Ở đó tất cả chúng ta nên cùng nhau tụng đọc, không nên tranh cãi, để đời sống phạm hạnh này được lâu bền, tồn tại dài lâu, vì lợi ích cho nhiều người, vì an vui cho nhiều người, vì thương đời, vì lợi ích, vì an vui cho chư thiên và loài người.",
  "dn33:1.8.1": "Một pháp ấy là gì?",
  "dn33:1.8.2": "Tất cả chúng sinh tồn tại nhờ thức ăn.",
  "dn33:1.8.3": "Tất cả chúng sinh tồn tại nhờ các hành.",
  "dn33:1.8.4": "Này các hiền giả, đây là một pháp đã được Thế Tôn, bậc biết rõ, thấy rõ, bậc A-la-hán, bậc Chánh Đẳng Giác, khéo giảng dạy.",
  "dn33:1.8.5": "Ở đây, tất cả đều phải cùng nhau kết tập, không được tranh cãi, để đời sống phạm hạnh này được lâu dài, bền vững, vì lợi ích cho nhiều người, vì hạnh phúc cho nhiều người, vì lòng thương đời, vì lợi ích, an vui cho chư thiên và loài người.",
  "dn33:1.9.0": "2. Pháp hai",
  "dn33:1.9.1": "Này các hiền giả, có hai pháp đã được Thế Tôn, bậc biết rõ, thấy rõ, bậc A-la-hán, bậc Chánh Đẳng Giác, khéo giảng dạy.",
  "dn33:1.9.2": "Ở đây, tất cả đều phải cùng nhau kết tập, không được tranh cãi, để đời sống phạm hạnh này được lâu dài, bền vững, vì lợi ích cho nhiều người, vì hạnh phúc cho nhiều người, vì lòng thương đời, vì lợi ích, an vui cho chư thiên và loài người.",
  "dn33:1.9.3": "Hai pháp ấy là gì?",
  "dn33:1.9.4": "Danh và sắc.",
  "dn33:1.9.5": "Vô minh và khát ái đối với hiện hữu.",
  "dn33:1.9.6": "Tà kiến về hiện hữu và tà kiến về không hiện hữu.",
  "dn33:1.9.7": "Không biết hổ thẹn và không biết sợ điều sai trái.",
  "dn33:1.9.8": "Biết hổ thẹn và biết sợ điều sai trái.",
  "dn33:1.9.9": "Khó dạy và bạn xấu.",
  "dn33:1.9.10": "Dễ dạy và bạn lành.",
  "dn33:1.9.11": "Khéo biết về tội phạm và khéo biết cách ra khỏi tội phạm.",
  "dn33:1.9.12": "Khéo biết về chứng nhập định và khéo biết cách ra khỏi chứng nhập định.",
  "dn33:1.9.13": "Khéo biết về các giới tố và khéo biết tác ý.",
  "dn33:1.9.14": "Khéo biết về các xứ và khéo biết duyên khởi.",
  "dn33:1.9.15": "Khéo biết điều có thể và điều không thể.",
  "dn33:1.9.16": "Ngay thẳng và biết xấu hổ.",
  "dn33:1.9.17": "Nhẫn nhịn và hiền hòa.",
  "dn33:1.9.18": "Dễ gần và tiếp đãi.",
  "dn33:1.9.19": "Không hại và trong sạch.",
  "dn33:1.9.20": "Thất niệm và thiếu tỉnh giác.",
  "dn33:1.9.21": "Niệm và tỉnh giác.",
  "dn33:1.9.22": "Không phòng hộ các căn và không biết chừng mực trong ăn uống.",
  "dn33:1.9.23": "Phòng hộ các căn và biết chừng mực trong ăn uống.",
  "dn33:1.9.24": "Sức mạnh của quán xét và sức mạnh của tu tập.",
  "dn33:1.9.25": "Sức mạnh của niệm và sức mạnh của định.",
  "dn33:1.9.26": "Chỉ và quán.",
  "dn33:1.9.27": "Tướng của chỉ và tướng của tinh tấn.",
  "dn33:1.9.28": "Tinh tấn và không tán loạn.",
  "dn33:1.9.29": "Giới hạnh hư hỏng và cái thấy hư hỏng.",
  "dn33:1.9.30": "Thành tựu giới hạnh và thành tựu chánh kiến.",
  "dn33:1.9.31": "Thanh tịnh giới hạnh và thanh tịnh cái thấy.",
  "dn33:1.9.32": "Còn thanh tịnh cái thấy là sự tinh cần của người có cái thấy đúng như thật.",
  "dn33:1.9.33": "Sự xúc động mạnh và sự tinh cần đúng đắn của người bị xúc động mạnh trước những chỗ đáng xúc động.",
  "dn33:1.9.34": "Không biết đủ trong các pháp lành và không chùn bước trong sự tinh cần.",
  "dn33:1.9.35": "Minh và giải thoát.",
  "dn33:1.9.36": "Trí biết sự diệt tận và trí biết sự không sinh khởi.",
  "dn33:1.9.37": "Này các hiền giả, đây là hai pháp đã được Thế Tôn, bậc biết rõ, thấy rõ, bậc A-la-hán, bậc Chánh Đẳng Giác, khéo giảng dạy.",
  "dn33:1.9.38": "Ở đây, tất cả đều phải cùng nhau kết tập, không được tranh cãi, để đời sống phạm hạnh này được lâu dài, bền vững, vì lợi ích cho nhiều người, vì hạnh phúc cho nhiều người, vì lòng thương đời, vì lợi ích, an vui cho chư thiên và loài người.",
  "dn33:1.10.0": "3. Pháp ba",
  "dn33:1.10.1": "Này các hiền giả, có ba pháp đã được Thế Tôn, bậc biết rõ, thấy rõ, bậc A-la-hán, bậc Chánh Đẳng Giác, khéo giảng dạy.",
  "dn33:1.10.2": "Ở đây, tất cả đều phải cùng nhau kết tập … vì lợi ích, an vui cho chư thiên và loài người.",
  "dn33:1.10.3": "Ba pháp ấy là gì?",
  "dn33:1.10.4": "Ba gốc bất thiện là—",
  "dn33:1.10.5": "tham là gốc bất thiện, sân là gốc bất thiện, si là gốc bất thiện.",
  "dn33:1.10.6": "Ba gốc thiện là—",
  "dn33:1.10.7": "không tham là gốc thiện, không sân là gốc thiện, không si là gốc thiện.",
  "dn33:1.10.8": "Ba hạnh xấu là—",
  "dn33:1.10.9": "thân làm ác, lời nói ác, ý nghĩ ác.",
  "dn33:1.10.10": "Ba hạnh lành—",
  "dn33:1.10.11": "thân làm lành, lời nói lành, ý nghĩ lành.",
  "dn33:1.10.12": "Ba tầm bất thiện—",
  "dn33:1.10.13": "tầm dục, tầm sân, tầm hại.",
  "dn33:1.10.14": "Ba tầm thiện—",
  "dn33:1.10.15": "tầm xuất ly, tầm không sân, tầm không hại.",
  "dn33:1.10.16": "Ba ý định bất thiện—",
  "dn33:1.10.17": "ý định dục, ý định sân, ý định hại.",
  "dn33:1.10.18": "Ba ý định thiện—",
  "dn33:1.10.19": "ý định xuất ly, ý định không sân, ý định không hại.",
  "dn33:1.10.20": "Ba tưởng bất thiện—",
  "dn33:1.10.21": "tưởng dục, tưởng sân, tưởng hại.",
  "dn33:1.10.22": "Ba tưởng thiện—",
  "dn33:1.10.23": "tưởng xuất ly, tưởng không sân, tưởng không hại.",
  "dn33:1.10.24": "Ba giới bất thiện—",
  "dn33:1.10.25": "giới dục, giới sân, giới hại.",
  "dn33:1.10.26": "Ba giới thiện—",
  "dn33:1.10.27": "giới xuất ly, giới không sân, giới không hại.",
  "dn33:1.10.28": "Lại có ba giới—",
  "dn33:1.10.29": "giới dục, giới sắc, giới vô sắc.",
  "dn33:1.10.30": "Lại có ba giới—",
  "dn33:1.10.31": "giới sắc, giới vô sắc, giới diệt.",
  "dn33:1.10.32": "Lại có ba giới—",
  "dn33:1.10.33": "giới thấp kém, giới trung bình, giới cao thượng.",
  "dn33:1.10.34": "Ba ái—",
  "dn33:1.10.35": "ái dục, ái hữu, ái phi hữu.",
  "dn33:1.10.36": "Lại có ba ái—",
  "dn33:1.10.37": "ái dục, ái sắc, ái vô sắc.",
  "dn33:1.10.38": "Lại có ba ái—",
  "dn33:1.10.39": "ái sắc, ái vô sắc, ái diệt.",
  "dn33:1.10.40": "Ba kiết sử—",
  "dn33:1.10.41": "thân kiến, nghi, chấp giữ giới cấm.",
  "dn33:1.10.42": "Ba lậu hoặc—",
  "dn33:1.10.43": "dục lậu, hữu lậu, vô minh lậu.",
  "dn33:1.10.44": "Ba hữu—",
  "dn33:1.10.45": "dục hữu, sắc hữu, vô sắc hữu.",
  "dn33:1.10.46": "Ba sự tìm cầu—",
  "dn33:1.10.47": "tìm cầu dục, tìm cầu hữu, tìm cầu đời sống phạm hạnh.",
  "dn33:1.10.48": "Ba cách so đo—",
  "dn33:1.10.49": "so đo rằng ‘ta hơn’, so đo rằng ‘ta bằng’, so đo rằng ‘ta kém’.",
  "dn33:1.10.50": "Ba thời—",
  "dn33:1.10.51": "thời quá khứ, thời vị lai, thời hiện tại.",
  "dn33:1.10.52": "Ba đầu mối—",
  "dn33:1.10.53": "thân kiến là đầu mối, sự sinh khởi của thân kiến là đầu mối, sự diệt của thân kiến là đầu mối.",
  "dn33:1.10.54": "Ba cảm thọ—",
  "dn33:1.10.55": "cảm thọ vui, cảm thọ khổ, cảm thọ không khổ không vui.",
  "dn33:1.10.56": "Ba loại khổ—",
  "dn33:1.10.57": "khổ vì khổ, khổ vì các hành, khổ vì đổi thay.",
  "dn33:1.10.58": "Ba nhóm—",
  "dn33:1.10.59": "Ba hạng: hạng nhất định sai lạc, hạng nhất định đúng đắn, hạng chưa nhất định.",
  "dn33:1.10.60": "Ba sự tối tăm—",
  "dn33:1.10.61": "nghi ngờ, phân vân, không quyết chắc, không vững tin khi nghĩ đến thời quá khứ; nghi ngờ, phân vân, không quyết chắc, không vững tin khi nghĩ đến thời tương lai; nghi ngờ, phân vân, không quyết chắc, không vững tin khi nghĩ đến thời hiện tại.",
  "dn33:1.10.62": "Ba điều Như Lai không cần giữ kín—",
  "dn33:1.10.63": "Này các hiền giả, Như Lai có thân hành trong sạch, không có hành vi xấu ác nơi thân nào mà Như Lai phải giữ kín rằng:",
  "dn33:1.10.64": "‘Mong người khác đừng biết điều này của ta.’",
  "dn33:1.10.65": "Này các hiền giả, Như Lai có lời nói trong sạch, không có hành vi xấu ác nơi lời nói nào mà Như Lai phải giữ kín rằng:",
  "dn33:1.10.66": "‘Mong người khác đừng biết điều này của ta.’",
  "dn33:1.10.67": "Này các hiền giả, Như Lai có ý hành trong sạch, không có hành vi xấu ác nơi ý nào mà Như Lai phải giữ kín rằng:",
  "dn33:1.10.68": "‘Mong người khác đừng biết điều này của ta.’",
  "dn33:1.10.69": "Ba sự trói buộc—",
  "dn33:1.10.70": "tham là trói buộc, sân là trói buộc, si là trói buộc.",
  "dn33:1.10.71": "Ba ngọn lửa—",
  "dn33:1.10.72": "lửa tham, lửa sân, lửa si.",
  "dn33:1.10.73": "Lại còn ba ngọn lửa nữa—",
  "dn33:1.10.74": "lửa đáng được cúng dường, lửa của người chủ nhà, lửa đáng được dâng vật thí.",
  "dn33:1.10.75": "Sự gồm thâu sắc có ba loại—",
  "dn33:1.10.76": "sắc thấy được và có ngăn ngại, sắc không thấy được nhưng có ngăn ngại, sắc không thấy được và không ngăn ngại.",
  "dn33:1.10.77": "Ba hành—",
  "dn33:1.10.78": "hành tạo phước, hành tạo không phước, hành tạo trạng thái bất động.",
  "dn33:1.10.79": "Ba hạng người—",
  "dn33:1.10.80": "người đang học, người không còn học, người không phải đang học cũng không phải không còn học.",
  "dn33:1.10.81": "Ba bậc trưởng lão—",
  "dn33:1.10.82": "trưởng lão do tuổi đời, trưởng lão do pháp, trưởng lão do sự công nhận.",
  "dn33:1.10.83": "Ba nền tảng làm phước—",
  "dn33:1.10.84": "nền tảng làm phước bằng bố thí, nền tảng làm phước bằng giữ giới, nền tảng làm phước bằng tu tập.",
  "dn33:1.10.85": "Ba căn cứ để khiển trách—",
  "dn33:1.10.86": "do thấy, do nghe, do nghi.",
  "dn33:1.10.87": "Ba sự tái sinh trong dục—",
  "dn33:1.10.88": "Này các hiền giả, có những chúng sinh có các dục hiện sẵn trước mặt; họ sống bị các dục hiện sẵn ấy chi phối, như loài người, một số chư thiên và một số chúng sinh ở cõi khổ.",
  "dn33:1.10.89": "Đây là sự tái sinh trong dục thứ nhất.",
  "dn33:1.10.90": "Này các hiền giả, có những chúng sinh tự tạo ra các dục; họ cứ tạo ra rồi hưởng các dục ấy, như chư thiên Hóa Lạc.",
  "dn33:1.10.91": "Đây là sự tái sinh trong dục thứ hai.",
  "dn33:1.10.92": "Này các hiền giả, có những chúng sinh hưởng các dục do kẻ khác tạo ra; họ sống bị các dục do kẻ khác tạo ấy chi phối, như chư thiên Tha Hóa Tự Tại.",
  "dn33:1.10.93": "Đây là sự tái sinh trong dục thứ ba.",
  "dn33:1.10.94": "Ba sự tái sinh trong lạc—",
  "dn33:1.10.95": "Này các hiền giả, có những chúng sinh cứ khởi lên lạc rồi an trú trong lạc, như chư thiên Phạm chúng.",
  "dn33:1.10.96": "Đây là sự tái sinh trong lạc thứ nhất.",
  "dn33:1.10.97": "Này các hiền giả, có những chúng sinh được thấm nhuần, chan hòa, đầy đủ, tràn ngập bởi lạc.",
  "dn33:1.10.98": "Thỉnh thoảng họ thốt lên lời cảm hứng rằng:",
  "dn33:1.10.99": "‘Ôi vui thay, ôi vui thay’, như chư thiên Quang Âm.",
  "dn33:1.10.100": "Đây là sự tái sinh trong lạc thứ hai.",
  "dn33:1.10.101": "Này các hiền giả, có những chúng sinh được thấm nhuần, chan hòa, đầy đủ, tràn ngập bởi lạc.",
  "dn33:1.10.102": "Họ cảm nhận lạc trong sự an tịnh và mãn nguyện ấy, như chư thiên Biến Tịnh.",
  "dn33:1.10.103": "Đây là sự tái sinh trong lạc thứ ba.",
  "dn33:1.10.104": "Ba loại trí tuệ—",
  "dn33:1.10.105": "trí tuệ của người đang học, trí tuệ của người không còn học, trí tuệ không phải của người đang học cũng không phải của người không còn học.",
  "dn33:1.10.106": "Lại còn ba loại trí tuệ nữa—",
  "dn33:1.10.107": "trí tuệ do suy nghĩ, trí tuệ do nghe học, trí tuệ do tu tập.",
  "dn33:1.10.108": "Ba thứ vũ khí—",
  "dn33:1.10.109": "vũ khí là nghe học, vũ khí là sống tách lặng, vũ khí là trí tuệ.",
  "dn33:1.10.110": "Ba căn —",
  "dn33:1.10.111": "căn của người sẽ biết điều chưa biết, căn của người đã biết, căn của người biết trọn vẹn.",
  "dn33:1.10.112": "Ba mắt —",
  "dn33:1.10.113": "mắt thịt, mắt trời, mắt trí tuệ.",
  "dn33:1.10.114": "Ba sự học —",
  "dn33:1.10.115": "học tăng thượng giới, học tăng thượng tâm, học tăng thượng tuệ.",
  "dn33:1.10.116": "Ba sự tu tập —",
  "dn33:1.10.117": "tu tập thân, tu tập tâm, tu tập trí tuệ.",
  "dn33:1.10.118": "Ba điều không gì hơn —",
  "dn33:1.10.119": "không gì hơn về thấy, không gì hơn về thực hành, không gì hơn về giải thoát.",
  "dn33:1.10.120": "Ba định —",
  "dn33:1.10.121": "định có tầm có tứ, định không tầm chỉ còn tứ, định không tầm không tứ.",
  "dn33:1.10.122": "Lại còn ba định nữa —",
  "dn33:1.10.123": "định không, định vô tướng, định vô nguyện.",
  "dn33:1.10.124": "Ba sự trong sạch —",
  "dn33:1.10.125": "thân trong sạch, lời nói trong sạch, ý trong sạch.",
  "dn33:1.10.126": "Ba sự lặng yên —",
  "dn33:1.10.127": "thân lặng yên, lời nói lặng yên, ý lặng yên.",
  "dn33:1.10.128": "Ba sự khéo léo —",
  "dn33:1.10.129": "khéo léo trong điều lợi ích, khéo léo trong điều không lợi ích, khéo léo trong phương cách.",
  "dn33:1.10.130": "Ba sự kiêu say —",
  "dn33:1.10.131": "kiêu say vì sức khỏe, kiêu say vì tuổi trẻ, kiêu say vì mạng sống.",
  "dn33:1.10.132": "Ba điều làm chủ —",
  "dn33:1.10.133": "lấy mình làm chủ, lấy đời làm chủ, lấy pháp làm chủ.",
  "dn33:1.10.134": "Ba đề tài nói chuyện —",
  "dn33:1.10.135": "hoặc nói chuyện dựa vào thời quá khứ:",
  "dn33:1.10.136": "‘Quá khứ đã là như vậy’;",
  "dn33:1.10.137": "hoặc nói chuyện dựa vào thời tương lai:",
  "dn33:1.10.138": "‘Tương lai sẽ là như vậy’;",
  "dn33:1.10.139": "hoặc nói chuyện dựa vào thời hiện tại ngay bây giờ:",
  "dn33:1.10.140": "‘Hiện tại bây giờ là như vậy’.",
  "dn33:1.10.141": "Ba minh —",
  "dn33:1.10.142": "minh là trí biết các đời sống trước, minh là trí biết sự chết và tái sinh của chúng sinh, minh là trí biết sự đoạn tận các lậu hoặc.",
  "dn33:1.10.143": "Ba cách an trú —",
  "dn33:1.10.144": "an trú như cõi trời, an trú như Phạm thiên, an trú của bậc thánh.",
  "dn33:1.10.145": "Ba phép mầu —",
  "dn33:1.10.146": "phép mầu thần thông, phép mầu biết tâm, phép mầu dạy bảo.",
  "dn33:1.10.147": "Này các hiền giả, đó là ba pháp đã được Thế Tôn, bậc biết, bậc thấy, bậc A-la-hán, bậc Chánh Đẳng Giác, khéo giảng dạy.",
  "dn33:1.10.148": "Ở đây, tất cả đều phải cùng nhau tụng đọc … vì lợi ích, vì an vui cho chư thiên và loài người.",
  "dn33:1.11.0": "4. Nhóm bốn",
  "dn33:1.11.1": "Này các hiền giả, có bốn pháp đã được Thế Tôn, bậc biết, bậc thấy, bậc A-la-hán, bậc Chánh Đẳng Giác, khéo giảng dạy.",
  "dn33:1.11.2": "Ở đây, tất cả đều phải cùng nhau tụng đọc, không nên tranh cãi … vì lợi ích, vì an vui cho chư thiên và loài người.",
  "dn33:1.11.3": "Bốn pháp ấy là gì?",
  "dn33:1.11.4": "Bốn nền tảng chánh niệm.",
  "dn33:1.11.5": "Ở đây, này các hiền giả, vị tỳ-kheo sống quán thân trên thân, nhiệt tâm, tỉnh biết, có chánh niệm, đã dẹp bỏ tham muốn và buồn bực đối với đời.",
  "dn33:1.11.6": "quán cảm thọ trên các cảm thọ …",
  "dn33:1.11.7": "quán tâm trên tâm …",
  "dn33:1.11.8": "sống quán pháp trên các pháp, nhiệt tâm, tỉnh biết, có chánh niệm, đã dẹp bỏ tham muốn và buồn bực đối với đời.",
  "dn33:1.11.9": "Bốn chánh cần.",
  "dn33:1.11.10": "Này hiền giả, ở đây vị tỳ kheo khởi lên ý muốn, cố gắng, phát khởi tinh tấn, thúc đẩy tâm, nỗ lực để các pháp xấu ác, bất thiện chưa sinh không sinh khởi.",
  "dn33:1.11.11": "Khởi lên ý muốn, cố gắng, phát khởi tinh tấn, thúc đẩy tâm, nỗ lực để đoạn trừ các pháp xấu ác, bất thiện đã sinh.",
  "dn33:1.11.12": "Khởi lên ý muốn, cố gắng, phát khởi tinh tấn, thúc đẩy tâm, nỗ lực để làm sinh khởi các pháp lành, thiện chưa sinh.",
  "dn33:1.11.13": "Khởi lên ý muốn, cố gắng, phát khởi tinh tấn, thúc đẩy tâm, nỗ lực để các pháp lành, thiện đã sinh được duy trì, không mất, tăng trưởng, rộng lớn, được tu tập và viên mãn.",
  "dn33:1.11.14": "Bốn nền tảng thành tựu.",
  "dn33:1.11.15": "Này hiền giả, ở đây vị tỳ kheo tu tập nền tảng thành tựu có định do dục và các nỗ lực tinh tấn đi kèm.",
  "dn33:1.11.16": "Tu tập nền tảng thành tựu có định do tâm và các nỗ lực tinh tấn đi kèm.",
  "dn33:1.11.17": "Tu tập nền tảng thành tựu có định do tinh tấn và các nỗ lực tinh tấn đi kèm.",
  "dn33:1.11.18": "Tu tập nền tảng thành tựu có định do quán xét và các nỗ lực tinh tấn đi kèm.",
  "dn33:1.11.19": "Bốn tầng thiền.",
  "dn33:1.11.20": "Này hiền giả, ở đây vị tỳ kheo lìa các dục, lìa các pháp bất thiện, chứng và an trú tầng thiền thứ nhất, có tầm có tứ, có hỷ lạc do ly dục sinh.",
  "dn33:1.11.21": "Khi tầm và tứ lắng xuống, nội tâm trong sáng, tâm chuyên nhất, không tầm không tứ, có hỷ lạc do định sinh, vị ấy chứng và an trú tầng thiền thứ hai.",
  "dn33:1.11.22": "Ly hỷ, vị ấy an trú xả, chánh niệm, tỉnh giác, và tự thân cảm nhận lạc, chứng và an trú tầng thiền thứ ba, mà các bậc thánh nói rằng: ‘Người có xả, có niệm, an trú trong lạc’.",
  "dn33:1.11.23": "Do đoạn trừ lạc, đoạn trừ khổ, và do hỷ ưu đã diệt từ trước, vị ấy chứng và an trú tầng thiền thứ tư, không khổ không lạc, thanh tịnh nhờ xả niệm.",
  "dn33:1.11.24": "Bốn cách tu tập định.",
  "dn33:1.11.25": "Này hiền giả, có cách tu tập định, khi được tu tập, được làm cho nhiều, sẽ đưa đến an trú an lạc ngay trong hiện tại.",
  "dn33:1.11.26": "Này hiền giả, có cách tu tập định, khi được tu tập, được làm cho nhiều, sẽ đưa đến đạt được trí và thấy.",
  "dn33:1.11.27": "Này hiền giả, có cách tu tập định, khi được tu tập, được làm cho nhiều, sẽ đưa đến chánh niệm và tỉnh giác.",
  "dn33:1.11.28": "Này hiền giả, có cách tu tập định, khi được tu tập, được làm cho nhiều, sẽ đưa đến diệt trừ các lậu hoặc.",
  "dn33:1.11.29": "Và này hiền giả, thế nào là cách tu tập định, khi được tu tập, được làm cho nhiều, sẽ đưa đến an trú an lạc ngay trong hiện tại?",
  "dn33:1.11.30": "Này hiền giả, ở đây vị tỳ kheo lìa các dục, lìa các pháp bất thiện, có tầm …",
  "dn33:1.11.31": "…",
  "dn33:1.11.32": "chứng và an trú tầng thiền thứ tư.",
  "dn33:1.11.33": "Này hiền giả, đó là cách tu tập định, khi được tu tập, được làm cho nhiều, sẽ đưa đến an trú an lạc ngay trong hiện tại.",
  "dn33:1.11.34": "Và này hiền giả, thế nào là cách tu tập định, khi được tu tập, được làm cho nhiều, sẽ đưa đến đạt được trí và thấy?",
  "dn33:1.11.35": "Này hiền giả, ở đây vị tỳ kheo tác ý đến tưởng ánh sáng, an trú tưởng ban ngày; như ban ngày thế nào thì ban đêm cũng vậy, như ban đêm thế nào thì ban ngày cũng vậy.",
  "dn33:1.11.36": "Như vậy, với tâm rộng mở, không bị che lấp, vị ấy tu tập tâm sáng chói.",
  "dn33:1.11.37": "Này hiền giả, đó là cách tu tập định, khi được tu tập, được làm cho nhiều, sẽ đưa đến đạt được trí và thấy.",
  "dn33:1.11.38": "Và này hiền giả, thế nào là cách tu tập định, khi được tu tập, được làm cho nhiều, sẽ đưa đến chánh niệm và tỉnh giác?",
  "dn33:1.11.39": "Này hiền giả, ở đây nơi vị tỳ kheo, các cảm thọ sinh khởi được biết rõ, hiện hữu được biết rõ, biến mất được biết rõ.",
  "dn33:1.11.40": "Các tưởng sinh khởi được biết rõ, hiện hữu được biết rõ, biến mất được biết rõ.",
  "dn33:1.11.41": "Các ý nghĩ sinh khởi được biết rõ, hiện hữu được biết rõ, biến mất được biết rõ.",
  "dn33:1.11.42": "Này hiền giả, đó là cách tu tập định, khi được tu tập, được làm cho nhiều, sẽ đưa đến chánh niệm và tỉnh giác.",
  "dn33:1.11.43": "Và này hiền giả, thế nào là cách tu tập định, khi được tu tập, được làm cho nhiều, sẽ đưa đến diệt trừ các lậu hoặc?",
  "dn33:1.11.44": "Này hiền giả, ở đây vị tỳ kheo sống quán sát sự sinh và diệt trong năm uẩn chấp thủ.",
  "dn33:1.11.45": "Như vầy là sắc, như vầy là sự sinh khởi của sắc, như vầy là sự diệt mất của sắc.",
  "dn33:1.11.46": "Như vầy là cảm thọ …",
  "dn33:1.11.47": "như vầy là tưởng …",
  "dn33:1.11.48": "như vầy là các hành …",
  "dn33:1.11.49": "như vầy là thức, như vầy là sự sinh khởi của thức, như vầy là sự diệt mất của thức.",
  "dn33:1.11.50": "Này hiền giả, đó là cách tu tập định, khi được tu tập, được làm cho nhiều, sẽ đưa đến diệt trừ các lậu hoặc.",
  "dn33:1.11.51": "Bốn tâm vô lượng.",
  "dn33:1.11.52": "Này hiền giả, ở đây vị tỳ kheo an trú, thấm nhuần một phương với tâm đi cùng lòng từ. Cũng vậy phương thứ hai. Cũng vậy phương thứ ba. Cũng vậy phương thứ tư. Như vậy, trên, dưới, ngang, khắp mọi nơi, đối với tất cả như nhau, vị ấy an trú, thấm nhuần toàn thế gian với tâm đi cùng lòng từ, rộng lớn, cao thượng, vô lượng, không oán, không hại.",
  "dn33:1.11.53": "Với tâm đi cùng lòng bi …",
  "dn33:1.11.54": "với tâm đi cùng lòng hỷ …",
  "dn33:1.11.55": "Với tâm đi cùng xả, vị ấy an trú, thấm nhuần một phương. Cũng vậy phương thứ hai. Cũng vậy phương thứ ba. Cũng vậy phương thứ tư. Như vậy, trên, dưới, ngang, khắp mọi nơi, đối với tất cả như nhau, vị ấy an trú, thấm nhuần toàn thế gian với tâm đi cùng xả, rộng lớn, cao thượng, vô lượng, không oán, không hại.",
  "dn33:1.11.56": "Bốn cảnh vô sắc.",
  "dn33:1.11.57": "Này hiền giả, ở đây vị tỳ kheo vượt hẳn mọi tưởng về sắc, do sự biến mất của tưởng va chạm, không tác ý đến các tưởng sai khác, nghĩ rằng: ‘Hư không là vô biên’, rồi chứng và an trú cảnh vô biên hư không.",
  "dn33:1.11.58": "Vượt hẳn cảnh vô biên hư không, nghĩ rằng: ‘Thức là vô biên’, rồi chứng và an trú cảnh vô biên thức.",
  "dn33:1.11.59": "Vượt hẳn cảnh vô biên thức, nghĩ rằng: ‘Không có gì cả’, rồi chứng và an trú cảnh không có gì cả.",
  "dn33:1.11.60": "Vượt hẳn xứ không có gì, vị ấy chứng và an trú trong xứ không tưởng cũng không phải không tưởng.",
  "dn33:1.11.61": "Bốn chỗ nương tựa.",
  "dn33:1.11.62": "Này hiền giả, ở đây vị tỳ-kheo có một điều dùng sau khi suy xét, một điều chịu đựng sau khi suy xét, một điều tránh né sau khi suy xét, một điều trừ bỏ sau khi suy xét.",
  "dn33:1.11.63": "Bốn truyền thống cao quý.",
  "dn33:1.11.64": "Này hiền giả, ở đây vị tỳ-kheo biết đủ với bất cứ loại y nào, và khen ngợi sự biết đủ với bất cứ loại y nào; không vì y mà rơi vào sự tìm cầu không thích hợp; khi không được y thì không bối rối, khi được y thì dùng không tham đắm, không mê muội, không dính mắc, thấy rõ sự nguy hại, có trí tuệ hướng đến thoát ra; và do sự biết đủ với bất cứ loại y nào ấy, vị ấy không tự đề cao mình, không chê bai người khác.",
  "dn33:1.11.65": "Vì nếu ở đây vị ấy khéo léo, không lười biếng, tỉnh giác, chánh niệm, thì này hiền giả, vị ấy được gọi là: ‘tỳ-kheo đứng vững trong truyền thống cao quý tối thượng xưa kia’.",
  "dn33:1.11.66": "Lại nữa, này hiền giả, vị tỳ-kheo biết đủ với bất cứ loại đồ ăn khất thực nào, và khen ngợi sự biết đủ với bất cứ loại đồ ăn khất thực nào; không vì đồ ăn khất thực mà rơi vào sự tìm cầu không thích hợp; khi không được đồ ăn khất thực thì không bối rối, khi được đồ ăn khất thực thì dùng không tham đắm, không mê muội, không dính mắc, thấy rõ sự nguy hại, có trí tuệ hướng đến thoát ra; và do sự biết đủ với bất cứ loại đồ ăn khất thực nào ấy, vị ấy không tự đề cao mình, không chê bai người khác.",
  "dn33:1.11.67": "Vì nếu ở đây vị ấy khéo léo, không lười biếng, tỉnh giác, chánh niệm, thì này hiền giả, vị ấy được gọi là: ‘tỳ-kheo đứng vững trong truyền thống cao quý tối thượng xưa kia’.",
  "dn33:1.11.68": "Lại nữa, này hiền giả, vị tỳ-kheo biết đủ với bất cứ loại chỗ ở nào, và khen ngợi sự biết đủ với bất cứ loại chỗ ở nào; không vì chỗ ở mà rơi vào sự tìm cầu không thích hợp; khi không được chỗ ở thì không bối rối, khi được chỗ ở thì dùng không tham đắm, không mê muội, không dính mắc, thấy rõ sự nguy hại, có trí tuệ hướng đến thoát ra; và do sự biết đủ với bất cứ loại chỗ ở nào ấy, vị ấy không tự đề cao mình, không chê bai người khác.",
  "dn33:1.11.69": "Vì nếu ở đây vị ấy khéo léo, không lười biếng, tỉnh giác, chánh niệm, thì này hiền giả, vị ấy được gọi là: ‘tỳ-kheo đứng vững trong truyền thống cao quý tối thượng xưa kia’.",
  "dn33:1.11.70": "Lại nữa, này hiền giả, vị tỳ-kheo vui thích từ bỏ, ưa thích từ bỏ; vui thích tu tập, ưa thích tu tập; và do sự vui thích từ bỏ, ưa thích từ bỏ, vui thích tu tập, ưa thích tu tập ấy, vị ấy không tự đề cao mình, không chê bai người khác.",
  "dn33:1.11.71": "Vì nếu ở đây vị ấy khéo léo, không lười biếng, tỉnh giác, chánh niệm, thì này hiền giả, vị ấy được gọi là: ‘tỳ-kheo đứng vững trong truyền thống cao quý tối thượng xưa kia’.",
  "dn33:1.11.72": "Bốn sự tinh cần.",
  "dn33:1.11.73": "Tinh cần phòng hộ, tinh cần đoạn trừ, tinh cần tu tập, tinh cần giữ gìn.",
  "dn33:1.11.74": "Và này hiền giả, thế nào là tinh cần phòng hộ?",
  "dn33:1.11.75": "Này hiền giả, ở đây vị tỳ-kheo khi mắt thấy sắc thì không nắm giữ tướng chung, không nắm giữ tướng riêng.",
  "dn33:1.11.76": "Vì nếu sống không phòng hộ căn mắt, thì tham muốn và buồn phiền, các pháp ác bất thiện có thể xâm nhập; nên vị ấy thực hành để phòng hộ, giữ gìn căn mắt, thành tựu sự phòng hộ nơi căn mắt.",
  "dn33:1.11.77": "Khi tai nghe tiếng …",
  "dn33:1.11.78": "khi mũi ngửi mùi …",
  "dn33:1.11.79": "khi lưỡi nếm vị …",
  "dn33:1.11.80": "khi thân chạm xúc chạm …",
  "dn33:1.11.81": "khi ý nhận biết pháp thì không nắm giữ tướng chung, không nắm giữ tướng riêng.",
  "dn33:1.11.82": "Vì nếu sống không phòng hộ căn ý, thì tham muốn và buồn phiền, các pháp ác bất thiện có thể xâm nhập; nên vị ấy thực hành để phòng hộ, giữ gìn căn ý, thành tựu sự phòng hộ nơi căn ý.",
  "dn33:1.11.83": "Này hiền giả, đó gọi là tinh cần phòng hộ.",
  "dn33:1.11.84": "Và này hiền giả, thế nào là tinh cần đoạn trừ?",
  "dn33:1.11.85": "Này các tỳ-kheo, ở đây vị tỳ-kheo không chấp nhận ý nghĩ dục đã khởi lên, từ bỏ, xua tan, làm cho chấm dứt, đưa đến không còn hiện hữu;",
  "dn33:1.11.86": "không chấp nhận ý nghĩ sân đã khởi lên …",
  "dn33:1.11.87": "không chấp nhận ý nghĩ hại đã khởi lên …",
  "dn33:1.11.88": "không chấp nhận các pháp ác bất thiện mỗi khi khởi lên, từ bỏ, xua tan, làm cho chấm dứt, đưa đến không còn hiện hữu.",
  "dn33:1.11.89": "Này hiền giả, đó gọi là tinh cần đoạn trừ.",
  "dn33:1.11.90": "Và này hiền giả, thế nào là tinh cần tu tập?",
  "dn33:1.11.91": "Này các tỳ-kheo, ở đây vị tỳ-kheo tu tập niệm giác chi, nương vào viễn ly, nương vào phai nhạt, nương vào chấm dứt, hướng đến buông bỏ,",
  "dn33:1.11.92": "tu tập trạch pháp giác chi …",
  "dn33:1.11.93": "tu tập tinh tấn giác chi …",
  "dn33:1.11.94": "tu tập hỷ giác chi …",
  "dn33:1.11.95": "tu tập khinh an giác chi …",
  "dn33:1.11.96": "tu tập định giác chi …",
  "dn33:1.11.97": "tu tập xả giác chi, nương vào viễn ly, nương vào phai nhạt, nương vào chấm dứt, hướng đến buông bỏ.",
  "dn33:1.11.98": "Này hiền giả, đó gọi là tinh cần tu tập.",
  "dn33:1.11.99": "Và này hiền giả, thế nào là tinh cần giữ gìn?",
  "dn33:1.11.100": "Này hiền giả, ở đây vị tỳ-kheo giữ gìn tướng định tốt đẹp đã khởi lên: tưởng bộ xương, tưởng xác bị dòi rúc, tưởng xác bầm xanh, tưởng xác bị chặt đứt, tưởng xác trương phồng.",
  "dn33:1.11.101": "Này hiền giả, đó gọi là tinh cần giữ gìn.",
  "dn33:1.11.102": "Bốn loại trí—",
  "dn33:1.11.103": "trí về pháp, trí về sự liên hệ, trí về sự bao quát, trí về quy ước.",
  "dn33:1.11.104": "Lại còn bốn loại trí khác—",
  "dn33:1.11.105": "trí về khổ, trí về nguồn gốc của khổ, trí về sự chấm dứt của khổ, trí về con đường đưa đến sự chấm dứt của khổ.",
  "dn33:1.11.106": "Bốn chi phần đưa đến dự lưu—",
  "dn33:1.11.107": "gần gũi người chân chánh, nghe chánh pháp, tác ý đúng đắn, thực hành đúng theo pháp.",
  "dn33:1.11.108": "Bốn chi phần của vị dự lưu.",
  "dn33:1.11.109": "Này hiền giả, ở đây người đệ tử bậc thánh đầy đủ lòng tin vững chắc đối với đức Phật:",
  "dn33:1.11.110": "‘Thế Tôn là bậc A-la-hán, bậc Chánh Đẳng Giác, đầy đủ trí và hạnh, khéo đi đến, hiểu rõ các cõi đời, bậc không ai hơn, người điều phục những ai cần được điều phục, thầy của chư thiên và loài người, là Phật, là Thế Tôn.’ ",
  "dn33:1.11.111": "Vị ấy đầy đủ lòng tin vững chắc đối với Pháp: ",
  "dn33:1.11.112": "‘Pháp được Thế Tôn khéo giảng, có thể thấy ngay trong hiện tại, không bị thời gian chi phối, đến để mà thấy, có khả năng hướng thượng, người có trí tự mình giác hiểu.’ ",
  "dn33:1.11.113": "Vị ấy đầy đủ lòng tin vững chắc đối với Tăng: ",
  "dn33:1.11.114": "‘Chúng đệ tử của Thế Tôn khéo thực hành, chúng đệ tử của Thế Tôn thực hành ngay thẳng, chúng đệ tử của Thế Tôn thực hành đúng đường, chúng đệ tử của Thế Tôn thực hành chân chánh; tức là bốn đôi, tám hạng người. Chúng đệ tử của Thế Tôn này xứng đáng được cúng dường, xứng đáng được tiếp đón, xứng đáng được dâng tặng, xứng đáng được chắp tay kính lễ, là ruộng phước vô thượng ở đời.’ ",
  "dn33:1.11.115": "Vị ấy đầy đủ những giới được bậc thánh yêu quý, không sứt mẻ, không rách vỡ, không lốm đốm, không tì vết, đem lại tự do, được người trí khen ngợi, không bị chấp thủ, đưa đến định. ",
  "dn33:1.11.116": "Bốn quả của đời sống xuất gia—",
  "dn33:1.11.117": "quả dự lưu, quả nhất lai, quả bất lai, quả A-la-hán. ",
  "dn33:1.11.118": "Bốn đại—",
  "dn33:1.11.119": "đại đất, đại nước, đại lửa, đại gió. ",
  "dn33:1.11.120": "Bốn món ăn—",
  "dn33:1.11.121": "đoàn thực, thô hoặc tế; xúc là thứ hai; tư niệm là thứ ba; thức là thứ tư. ",
  "dn33:1.11.122": "Bốn chỗ đứng của thức. ",
  "dn33:1.11.123": "Này các hiền giả, nếu thức đứng vững nơi sắc, lấy sắc làm chỗ dựa, lấy sắc làm đối tượng, được tưới tẩm bởi sự ưa thích, thì nó tăng trưởng, lớn mạnh, phát triển rộng ra; ",
  "dn33:1.11.124": "hoặc nơi thọ, này các hiền giả… ",
  "dn33:1.11.125": "hoặc nơi tưởng, này các hiền giả… ",
  "dn33:1.11.126": "hoặc nơi các hành, này các hiền giả, nếu thức đứng vững thì đứng trên các hành, lấy các hành làm đối tượng, lấy các hành làm chỗ dựa, được tưới tẩm bởi sự ưa thích, thì nó tăng trưởng, lớn mạnh, phát triển rộng ra. ",
  "dn33:1.11.127": "Bốn lối thiên lệch—",
  "dn33:1.11.128": "thiên lệch vì ưa thích, thiên lệch vì ghét bỏ, thiên lệch vì si mê, thiên lệch vì sợ hãi. ",
  "dn33:1.11.129": "Bốn chỗ sinh khởi của ái—",
  "dn33:1.11.130": "này các hiền giả, nơi vị tỳ-kheo, ái khi sinh khởi thì sinh khởi vì y áo; ",
  "dn33:1.11.131": "này các hiền giả, nơi vị tỳ-kheo, ái khi sinh khởi thì sinh khởi vì đồ ăn khất thực; ",
  "dn33:1.11.132": "này các hiền giả, nơi vị tỳ-kheo, ái khi sinh khởi thì sinh khởi vì chỗ ở; ",
  "dn33:1.11.133": "này các hiền giả, nơi vị tỳ-kheo, ái khi sinh khởi thì sinh khởi vì có mặt hay không có mặt. ",
  "dn33:1.11.134": "Bốn cách thực hành—",
  "dn33:1.11.135": "cách thực hành khổ, chứng ngộ chậm; cách thực hành khổ, chứng ngộ nhanh; cách thực hành lạc, chứng ngộ chậm; cách thực hành lạc, chứng ngộ nhanh. ",
  "dn33:1.11.136": "Lại còn bốn cách thực hành khác—",
  "dn33:1.11.137": "cách thực hành không nhẫn chịu, cách thực hành nhẫn chịu, cách thực hành tự chế, cách thực hành an hòa. ",
  "dn33:1.11.138": "Bốn nền tảng của pháp—",
  "dn33:1.11.139": "không tham muốn là nền tảng của pháp, không ác ý là nền tảng của pháp, chánh niệm là nền tảng của pháp, chánh định là nền tảng của pháp. ",
  "dn33:1.11.140": "Bốn cách nắm giữ pháp—",
  "dn33:1.11.141": "này các hiền giả, có cách nắm giữ pháp đưa đến khổ trong hiện tại và cho quả khổ về sau. ",
  "dn33:1.11.142": "Này các hiền giả, có cách nắm giữ pháp đưa đến khổ trong hiện tại nhưng cho quả vui về sau. ",
  "dn33:1.11.143": "Này các hiền giả, có cách nắm giữ pháp đưa đến vui trong hiện tại nhưng cho quả khổ về sau. ",
  "dn33:1.11.144": "Này các hiền giả, có cách nắm giữ pháp đưa đến vui trong hiện tại và cho quả vui về sau. ",
  "dn33:1.11.145": "Bốn nhóm pháp—",
  "dn33:1.11.146": "nhóm giới, nhóm định, nhóm tuệ, nhóm giải thoát. ",
  "dn33:1.11.147": "Bốn sức mạnh—",
  "dn33:1.11.148": "sức mạnh tinh tấn, sức mạnh chánh niệm, sức mạnh định, sức mạnh tuệ. ",
  "dn33:1.11.149": "Bốn chỗ nương vững chắc—",
  "dn33:1.11.150": "lấy tuệ làm chỗ nương vững chắc, lấy sự thật làm chỗ nương vững chắc, lấy buông xả làm chỗ nương vững chắc, lấy lắng dịu làm chỗ nương vững chắc. ",
  "dn33:1.11.151": "Bốn cách trả lời câu hỏi—",
  "dn33:1.11.152": "câu hỏi cần trả lời dứt khoát, câu hỏi cần trả lời bằng cách hỏi lại, câu hỏi cần trả lời bằng cách phân tích, câu hỏi cần gác lại. ",
  "dn33:1.11.153": "Bốn loại nghiệp—",
  "dn33:1.11.154": "này các hiền giả, có nghiệp đen cho quả đen. ",
  "dn33:1.11.155": "Này các hiền giả, có nghiệp trắng cho quả trắng. ",
  "dn33:1.11.156": "Này các hiền giả, có nghiệp đen trắng cho quả đen trắng. ",
  "dn33:1.11.157": "Này các hiền giả, có nghiệp không đen không trắng, cho quả không đen không trắng, đưa đến sự chấm dứt nghiệp. ",
  "dn33:1.11.158": "Bốn pháp cần được tự mình chứng ngộ—",
  "dn33:1.11.159": "đời sống trước đây cần được tự mình chứng ngộ bằng chánh niệm; ",
  "dn33:1.11.160": "Sự chết đi và tái sinh của chúng sinh cần được chứng ngộ bằng mắt.",
  "dn33:1.11.161": "Tám giải thoát cần được chứng ngộ bằng thân.",
  "dn33:1.11.162": "Sự diệt tận các lậu hoặc cần được chứng ngộ bằng trí tuệ.",
  "dn33:1.11.163": "Bốn dòng thác là—",
  "dn33:1.11.164": "dòng thác dục, dòng thác hiện hữu, dòng thác tà kiến, dòng thác vô minh.",
  "dn33:1.11.165": "Bốn ách trói là—",
  "dn33:1.11.166": "ách trói dục, ách trói hiện hữu, ách trói tà kiến, ách trói vô minh.",
  "dn33:1.11.167": "Bốn sự lìa khỏi ách trói là—",
  "dn33:1.11.168": "lìa khỏi ách trói dục, lìa khỏi ách trói hiện hữu, lìa khỏi ách trói tà kiến, lìa khỏi ách trói vô minh.",
  "dn33:1.11.169": "Bốn nút buộc là—",
  "dn33:1.11.170": "tham muốn là nút buộc của thân, sân hận là nút buộc của thân, chấp thủ giới cấm là nút buộc của thân, chấp chặt rằng ‘chỉ điều này là thật’ là nút buộc của thân.",
  "dn33:1.11.171": "Bốn sự chấp thủ là—",
  "dn33:1.11.172": "chấp thủ dục, chấp thủ tà kiến, chấp thủ giới cấm, chấp thủ thuyết ngã.",
  "dn33:1.11.173": "Bốn loại sinh là—",
  "dn33:1.11.174": "sinh từ trứng, sinh từ bào thai, sinh từ ẩm thấp, sinh hóa sinh.",
  "dn33:1.11.175": "Bốn cách đi vào thai mẹ.",
  "dn33:1.11.176": "Này các hiền hữu, ở đây có người đi vào thai mẹ mà không biết rõ, ở trong thai mẹ mà không biết rõ, ra khỏi thai mẹ mà không biết rõ; đó là cách đi vào thai mẹ thứ nhất.",
  "dn33:1.11.177": "Lại nữa, này các hiền hữu, ở đây có người đi vào thai mẹ mà biết rõ, ở trong thai mẹ mà không biết rõ, ra khỏi thai mẹ mà không biết rõ; đó là cách đi vào thai mẹ thứ hai.",
  "dn33:1.11.178": "Lại nữa, này các hiền hữu, ở đây có người đi vào thai mẹ mà biết rõ, ở trong thai mẹ mà biết rõ, ra khỏi thai mẹ mà không biết rõ; đó là cách đi vào thai mẹ thứ ba.",
  "dn33:1.11.179": "Lại nữa, này các hiền hữu, ở đây có người đi vào thai mẹ mà biết rõ, ở trong thai mẹ mà biết rõ, ra khỏi thai mẹ mà biết rõ; đó là cách đi vào thai mẹ thứ tư.",
  "dn33:1.11.180": "Bốn cách đạt được thân này.",
  "dn33:1.11.181": "Này các hiền hữu, có cách đạt được thân này, trong đó chỉ có ý muốn của chính mình tác động, không phải ý muốn của người khác.",
  "dn33:1.11.182": "Này các hiền hữu, có cách đạt được thân này, trong đó chỉ có ý muốn của người khác tác động, không phải ý muốn của chính mình.",
  "dn33:1.11.183": "Này các hiền hữu, có cách đạt được thân này, trong đó cả ý muốn của chính mình lẫn ý muốn của người khác đều tác động.",
  "dn33:1.11.184": "Này các hiền hữu, có cách đạt được thân này, trong đó không phải ý muốn của chính mình tác động, cũng không phải ý muốn của người khác.",
  "dn33:1.11.185": "Bốn sự thanh tịnh của vật cúng dường.",
  "dn33:1.11.186": "Này các hiền hữu, có vật cúng dường được thanh tịnh do người cho, không phải do người nhận.",
  "dn33:1.11.187": "Này các hiền hữu, có vật cúng dường được thanh tịnh do người nhận, không phải do người cho.",
  "dn33:1.11.188": "Này các hiền hữu, có vật cúng dường không thanh tịnh do người cho, cũng không do người nhận.",
  "dn33:1.11.189": "Này các hiền hữu, có vật cúng dường được thanh tịnh cả do người cho lẫn do người nhận.",
  "dn33:1.11.190": "Bốn cách thu phục lòng người là—",
  "dn33:1.11.191": "bố thí, lời nói dễ mến, làm việc lợi ích, đối xử bình đẳng.",
  "dn33:1.11.192": "Bốn cách nói không cao thượng là—",
  "dn33:1.11.193": "nói dối, nói hai lưỡi, nói lời thô ác, nói chuyện phù phiếm.",
  "dn33:1.11.194": "Bốn cách nói cao thượng là—",
  "dn33:1.11.195": "tránh nói dối, tránh nói hai lưỡi, tránh nói lời thô ác, tránh nói chuyện phù phiếm.",
  "dn33:1.11.196": "Lại còn bốn cách nói không cao thượng nữa là—",
  "dn33:1.11.197": "điều không thấy mà nói là thấy, điều không nghe mà nói là nghe, điều không cảm nhận mà nói là cảm nhận, điều không biết mà nói là biết.",
  "dn33:1.11.198": "Lại còn bốn cách nói cao thượng nữa là—",
  "dn33:1.11.199": "điều không thấy thì nói là không thấy, điều không nghe thì nói là không nghe, điều không cảm nhận thì nói là không cảm nhận, điều không biết thì nói là không biết.",
  "dn33:1.11.200": "Lại còn bốn cách nói không cao thượng nữa là—",
  "dn33:1.11.201": "điều đã thấy mà nói là không thấy, điều đã nghe mà nói là không nghe, điều đã cảm nhận mà nói là không cảm nhận, điều đã biết mà nói là không biết.",
  "dn33:1.11.202": "Lại còn bốn cách nói cao thượng nữa là—",
  "dn33:1.11.203": "điều đã thấy thì nói là đã thấy, điều đã nghe thì nói là đã nghe, điều đã cảm nhận thì nói là đã cảm nhận, điều đã biết thì nói là đã biết.",
  "dn33:1.11.204": "Bốn hạng người.",
  "dn33:1.11.205": "Này các hiền hữu, ở đây có người tự hành hạ mình, chuyên sống theo cách làm khổ chính mình.",
  "dn33:1.11.206": "Này các hiền hữu, ở đây có người hành hạ người khác, chuyên sống theo cách làm khổ người khác.",
  "dn33:1.11.207": "Này các hiền hữu, ở đây có người vừa tự hành hạ mình, chuyên sống theo cách làm khổ chính mình, vừa hành hạ người khác, chuyên sống theo cách làm khổ người khác.",
  "dn33:1.11.208": "Này các hiền hữu, ở đây có người không tự hành hạ mình, không chuyên sống theo cách làm khổ chính mình, cũng không hành hạ người khác, không chuyên sống theo cách làm khổ người khác.",
  "dn33:1.11.209": "Người ấy không tự hành hạ mình, không hành hạ người khác, ngay trong đời này sống không đói khát, tịch tĩnh, mát dịu, cảm nhận an lạc, sống với tự thân như Phạm thiên.",
  "dn33:1.11.210": "Lại có bốn hạng người.",
  "dn33:1.11.211": "Này các hiền giả, ở đây có người thực hành vì lợi ích cho mình, không vì lợi ích cho người.",
  "dn33:1.11.212": "Này các hiền giả, ở đây có người thực hành vì lợi ích cho người, không vì lợi ích cho mình.",
  "dn33:1.11.213": "Này các hiền giả, ở đây có người không thực hành vì lợi ích cho mình, cũng không vì lợi ích cho người.",
  "dn33:1.11.214": "Này các hiền giả, ở đây có người thực hành vì lợi ích cho mình và vì lợi ích cho người.",
  "dn33:1.11.215": "Lại có bốn hạng người—",
  "dn33:1.11.216": "từ tối đi đến tối, từ tối đi đến sáng, từ sáng đi đến tối, từ sáng đi đến sáng.",
  "dn33:1.11.217": "Lại có bốn hạng người—",
  "dn33:1.11.218": "sa-môn bất động, sa-môn hoa sen xanh, sa-môn hoa sen trắng, sa-môn mềm mịn nhất trong các sa-môn.",
  "dn33:1.11.219": "Này các hiền giả, đây là bốn pháp đã được Thế Tôn ấy, bậc biết, bậc thấy, bậc A-la-hán, bậc Chánh Đẳng Giác, khéo giảng dạy;",
  "dn33:1.11.220": "ở đây tất cả đều phải được cùng nhau tụng đọc … vì lợi ích, vì an vui cho chư thiên và loài người.",
  "dn33:1.11.221": "Phần tụng đọc thứ nhất đã xong.",
  "dn33:2.1.0": "5. Nhóm năm",
  "dn33:2.1.1": "Này các hiền giả, có năm pháp đã được Thế Tôn ấy, bậc biết, bậc thấy, bậc A-la-hán, bậc Chánh Đẳng Giác, khéo giảng dạy.",
  "dn33:2.1.2": "Ở đây tất cả đều phải được cùng nhau tụng đọc … vì lợi ích, vì an vui cho chư thiên và loài người.",
  "dn33:2.1.3": "Năm pháp ấy là gì?",
  "dn33:2.1.4": "Năm uẩn.",
  "dn33:2.1.5": "Sắc uẩn, thọ uẩn, tưởng uẩn, hành uẩn, thức uẩn.",
  "dn33:2.1.6": "Năm uẩn chấp thủ.",
  "dn33:2.1.7": "Sắc uẩn chấp thủ, thọ uẩn chấp thủ, tưởng uẩn chấp thủ, hành uẩn chấp thủ, thức uẩn chấp thủ.",
  "dn33:2.1.8": "Năm dây dục.",
  "dn33:2.1.9": "Các sắc do mắt nhận biết, đáng ưa, dễ mến, vừa ý, khả ái, gắn với dục, làm khởi tham,",
  "dn33:2.1.10": "các tiếng do tai nhận biết …",
  "dn33:2.1.11": "các mùi do mũi nhận biết …",
  "dn33:2.1.12": "các vị do lưỡi nhận biết …",
  "dn33:2.1.13": "các xúc do thân nhận biết, đáng ưa, dễ mến, vừa ý, khả ái, gắn với dục, làm khởi tham.",
  "dn33:2.1.14": "Năm đường đi—",
  "dn33:2.1.15": "địa ngục, loài vật, ngạ quỷ, loài người, chư thiên.",
  "dn33:2.1.16": "Năm sự keo kiệt—",
  "dn33:2.1.17": "keo kiệt chỗ ở, keo kiệt gia đình quen biết, keo kiệt lợi lộc, keo kiệt tiếng tốt, keo kiệt pháp.",
  "dn33:2.1.18": "Năm chướng ngại—",
  "dn33:2.1.19": "chướng ngại do ham muốn dục, chướng ngại do ác ý, chướng ngại do hôn trầm buồn ngủ, chướng ngại do xao động hối quá, chướng ngại do nghi ngờ.",
  "dn33:2.1.20": "Năm trói buộc phần thấp—",
  "dn33:2.1.21": "thân kiến, nghi ngờ, chấp giữ giới cấm và nghi thức, ham muốn dục, ác ý.",
  "dn33:2.1.22": "Năm trói buộc phần cao—",
  "dn33:2.1.23": "ham muốn cõi sắc, ham muốn cõi vô sắc, ngã mạn, xao động, vô minh.",
  "dn33:2.1.24": "Năm điều học—",
  "dn33:2.1.25": "tránh sát sinh, tránh lấy của không cho, tránh tà hạnh trong dục, tránh nói dối, tránh rượu men rượu nấu và các chất say làm sinh buông lung.",
  "dn33:2.1.26": "Năm việc không thể xảy ra.",
  "dn33:2.1.27": "Này các hiền giả, vị tỳ-kheo đã hết lậu hoặc không thể cố ý tước đoạt mạng sống của một sinh vật. Vị tỳ-kheo đã hết lậu hoặc không thể lấy vật không được cho, bị xem là trộm cắp. Vị tỳ-kheo đã hết lậu hoặc không thể hành dâm. Vị tỳ-kheo đã hết lậu hoặc không thể cố ý nói dối khi biết rõ. Vị tỳ-kheo đã hết lậu hoặc không thể hưởng thụ các dục bằng cách cất chứa để dùng, như khi trước còn sống tại gia.",
  "dn33:2.1.28": "Năm sự suy sụp—",
  "dn33:2.1.29": "suy sụp về bà con, suy sụp về tài sản, suy sụp vì bệnh tật, suy sụp về giới hạnh, suy sụp về cái thấy.",
  "dn33:2.1.30": "Này các hiền giả, chúng sinh không phải vì suy sụp về bà con, hay vì suy sụp về tài sản, hay vì suy sụp vì bệnh tật mà sau khi thân hoại mạng chung sinh vào cõi dữ, đường xấu, chỗ đọa, địa ngục.",
  "dn33:2.1.31": "Này các hiền giả, chính vì suy sụp về giới hạnh hoặc vì suy sụp về cái thấy mà chúng sinh sau khi thân hoại mạng chung sinh vào cõi dữ, đường xấu, chỗ đọa, địa ngục.",
  "dn33:2.1.32": "Năm sự thành tựu—",
  "dn33:2.1.33": "thành tựu về bà con, thành tựu về tài sản, thành tựu về sức khỏe, thành tựu về giới hạnh, thành tựu về cái thấy.",
  "dn33:2.1.34": "Này các hiền giả, chúng sinh không phải vì thành tựu về bà con, hay vì thành tựu về tài sản, hay vì thành tựu về sức khỏe mà sau khi thân hoại mạng chung sinh vào cõi lành, cõi trời.",
  "dn33:2.1.35": "Này các hiền giả, chính vì thành tựu về giới hạnh hoặc vì thành tựu về cái thấy mà chúng sinh sau khi thân hoại mạng chung sinh vào cõi lành, cõi trời.",
  "dn33:2.1.36": "Năm điều nguy hại của người thiếu giới do hư hỏng giới hạnh.",
  "dn33:2.1.37": "Này các hiền giả, ở đây người thiếu giới, hư hỏng giới hạnh, do sống buông lung nên bị tổn thất lớn về tài sản,",
  "dn33:2.1.38": "Đây là điều tai hại thứ nhất của người thiếu giới hạnh do giới bị hư hoại.",
  "dn33:2.1.39": "Lại nữa, này các hiền giả, người thiếu giới hạnh, giới bị hư hoại, tiếng xấu lan rộng,",
  "dn33:2.1.40": "đây là điều tai hại thứ hai của người thiếu giới hạnh do giới bị hư hoại.",
  "dn33:2.1.41": "Lại nữa, này các hiền giả, người thiếu giới hạnh, giới bị hư hoại, khi đến bất cứ hội chúng nào, dù là hội chúng vua chúa, hội chúng bà-la-môn, hội chúng gia chủ hay hội chúng sa-môn, đều đến với vẻ thiếu tự tin, bối rối,",
  "dn33:2.1.42": "đây là điều tai hại thứ ba của người thiếu giới hạnh do giới bị hư hoại.",
  "dn33:2.1.43": "Lại nữa, này các hiền giả, người thiếu giới hạnh, giới bị hư hoại, khi chết thì tâm trí rối loạn,",
  "dn33:2.1.44": "đây là điều tai hại thứ tư của người thiếu giới hạnh do giới bị hư hoại.",
  "dn33:2.1.45": "Lại nữa, này các hiền giả, người thiếu giới hạnh, giới bị hư hoại, khi thân hoại mạng chung, sau khi chết sinh vào cõi dữ, đường ác, chỗ sa đọa, địa ngục,",
  "dn33:2.1.46": "đây là điều tai hại thứ năm của người thiếu giới hạnh do giới bị hư hoại.",
  "dn33:2.1.47": "Có năm lợi ích của người có giới do giới được đầy đủ.",
  "dn33:2.1.48": "Ở đây, này các hiền giả, người có giới, giới được đầy đủ, nhờ sống không phóng dật mà đạt được khối tài sản lớn,",
  "dn33:2.1.49": "đây là lợi ích thứ nhất của người có giới do giới được đầy đủ.",
  "dn33:2.1.50": "Lại nữa, này các hiền giả, người có giới, giới được đầy đủ, tiếng tốt lan rộng,",
  "dn33:2.1.51": "đây là lợi ích thứ hai của người có giới do giới được đầy đủ.",
  "dn33:2.1.52": "Lại nữa, này các hiền giả, người có giới, giới được đầy đủ, khi đến bất cứ hội chúng nào, dù là hội chúng vua chúa, hội chúng bà-la-môn, hội chúng gia chủ hay hội chúng sa-môn, đều đến với sự tự tin, không bối rối,",
  "dn33:2.1.53": "đây là lợi ích thứ ba của người có giới do giới được đầy đủ.",
  "dn33:2.1.54": "Lại nữa, này các hiền giả, người có giới, giới được đầy đủ, khi chết thì tâm trí không rối loạn,",
  "dn33:2.1.55": "đây là lợi ích thứ tư của người có giới do giới được đầy đủ.",
  "dn33:2.1.56": "Lại nữa, này các hiền giả, người có giới, giới được đầy đủ, khi thân hoại mạng chung, sau khi chết sinh vào cõi lành, cõi trời, thế giới chư thiên,",
  "dn33:2.1.57": "đây là lợi ích thứ năm của người có giới do giới được đầy đủ.",
  "dn33:2.1.58": "Này các hiền giả, vị tỳ-kheo muốn khiển trách người khác, trước hết phải tự đặt vững năm pháp này trong mình rồi mới khiển trách người khác.",
  "dn33:2.1.59": "Ta sẽ nói đúng lúc, không nói không đúng lúc,",
  "dn33:2.1.60": "ta sẽ nói điều thật, không nói điều không thật,",
  "dn33:2.1.61": "ta sẽ nói lời mềm mỏng, không nói lời thô bạo,",
  "dn33:2.1.62": "ta sẽ nói điều có ích, không nói điều vô ích,",
  "dn33:2.1.63": "ta sẽ nói với tâm từ, không nói với lòng giận dữ.",
  "dn33:2.1.64": "Này các hiền giả, vị tỳ-kheo muốn khiển trách người khác phải tự đặt vững năm pháp này trong mình rồi mới khiển trách người khác.",
  "dn33:2.1.65": "Có năm yếu tố của sự tinh cần.",
  "dn33:2.1.66": "Ở đây, này các hiền giả, vị tỳ-kheo có lòng tin, tin vào sự giác ngộ của Như Lai:",
  "dn33:2.1.67": "‘Thế Tôn là bậc A-la-hán, bậc Chánh Đẳng Giác, đầy đủ trí và hạnh, khéo đi đến, hiểu rõ thế gian, bậc dẫn dắt người cần được điều phục không ai hơn, bậc thầy của chư thiên và loài người, là Phật, là Thế Tôn.’",
  "dn33:2.1.68": "Vị ấy ít bệnh, ít não, có sức tiêu hóa điều hòa, không quá lạnh, không quá nóng, ở mức vừa phải, chịu đựng được sự tinh cần.",
  "dn33:2.1.69": "Vị ấy không gian dối, không giả vờ, bộc lộ đúng như thật về mình với bậc đạo sư hoặc với các vị đồng phạm hạnh có trí.",
  "dn33:2.1.70": "Vị ấy sống tinh tấn để đoạn trừ các pháp bất thiện, để thành tựu các pháp thiện, vững mạnh, kiên quyết nỗ lực, không bỏ gánh nặng đối với các pháp thiện.",
  "dn33:2.1.71": "Vị ấy có trí, đầy đủ trí tuệ đưa đến thấy sự sinh diệt, là trí tuệ của bậc thánh, thấu suốt, đưa đến chấm dứt khổ một cách đúng đắn.",
  "dn33:2.1.72": "Có năm cõi tịnh cư —",
  "dn33:2.1.73": "Vô Phiền, Vô Nhiệt, Thiện Hiện, Thiện Kiến, Sắc Cứu Cánh.",
  "dn33:2.1.74": "Có năm hạng bất lai —",
  "dn33:2.1.75": "vị nhập niết-bàn ở khoảng giữa, vị nhập niết-bàn khi vừa tái sinh, vị nhập niết-bàn không cần cố gắng thêm, vị nhập niết-bàn cần cố gắng thêm, vị đi lên dòng cao đến cõi Sắc Cứu Cánh.",
  "dn33:2.1.76": "Có năm sự chai cứng của tâm.",
  "dn33:2.1.77": "Ở đây, này các hiền giả, vị tỳ-kheo nghi ngờ, phân vân đối với bậc đạo sư, không quyết tin, không vững lòng.",
  "dn33:2.1.78": "Này các hiền giả, vị tỳ-kheo nào nghi ngờ, phân vân đối với bậc đạo sư, không quyết tin, không vững lòng, thì tâm vị ấy không hướng đến sự nhiệt tâm, chuyên cần, bền bỉ, tinh tấn; tâm không hướng đến sự nhiệt tâm, chuyên cần, bền bỉ, tinh tấn như vậy là sự chai cứng của tâm thứ nhất.",
  "dn33:2.1.79": "Lại nữa, này các hiền giả, vị tỳ-kheo nghi ngờ, phân vân đối với pháp …",
  "dn33:2.1.80": "nghi ngờ, phân vân đối với tăng …",
  "dn33:2.1.81": "nghi ngờ, phân vân đối với học pháp …",
  "dn33:2.1.82": "đối với các vị đồng phạm hạnh thì giận dữ, không vui lòng, tâm bị tổn thương, trở nên chai cứng.",
  "dn33:2.1.83": "Này các hiền giả, vị tỳ-kheo nào đối với các vị đồng phạm hạnh thì giận dữ, không vui lòng, tâm bị tổn thương, trở nên chai cứng, thì tâm vị ấy không hướng đến sự nhiệt tâm, chuyên cần, bền bỉ, tinh tấn; tâm không hướng đến sự nhiệt tâm, chuyên cần, bền bỉ, tinh tấn như vậy là sự chai cứng của tâm thứ năm.",
  "dn33:2.1.84": "Có năm sự trói buộc của tâm.",
  "dn33:2.1.85": "Ở đây, này các hiền giả, vị tỳ-kheo chưa lìa tham đối với các dục, chưa hết ham muốn, chưa hết yêu thích, chưa hết khát khao, chưa hết nung nấu, chưa hết ái dục.",
  "dn33:2.1.86": "Này các hiền giả, vị tỳ-kheo nào chưa lìa tham đối với các dục, chưa hết ham muốn, chưa hết yêu thích, chưa hết khát khao, chưa hết nung nấu, chưa hết ái dục, thì tâm vị ấy không hướng đến sự nhiệt tâm, chuyên cần, bền bỉ, tinh tấn.",
  "dn33:2.1.87": "Người có tâm không hướng đến sự nhiệt tâm, chuyên cần, bền bỉ, tinh tấn.",
  "dn33:2.1.88": "Đây là sự trói buộc thứ nhất của tâm.",
  "dn33:2.1.89": "Lại nữa, này các hiền giả, vị tỳ-kheo chưa lìa tham đối với thân …",
  "dn33:2.1.90": "chưa lìa tham đối với sắc …",
  "dn33:2.1.91": "lại nữa, này các hiền giả, vị tỳ-kheo ăn cho đầy bụng, no nê, rồi sống đắm theo sự dễ chịu khi nằm, sự dễ chịu khi nghỉ, sự dễ chịu do buồn ngủ …",
  "dn33:2.1.92": "lại nữa, này các hiền giả, vị tỳ-kheo sống phạm hạnh với ước nguyện được sinh vào một cõi trời nào đó: ‘Nhờ giới này, hay hạnh này, hay khổ hạnh này, hay đời sống phạm hạnh này, ta sẽ thành chư thiên hay một vị trời nào đó.’",
  "dn33:2.1.93": "Này các hiền giả, vị tỳ-kheo nào sống phạm hạnh với ước nguyện được sinh vào một cõi trời nào đó: ‘Nhờ giới này, hay hạnh này, hay khổ hạnh này, hay đời sống phạm hạnh này, ta sẽ thành chư thiên hay một vị trời nào đó’, thì tâm vị ấy không hướng đến sự tinh cần, chuyên tâm, bền bỉ, nỗ lực. Người nào tâm không hướng đến sự tinh cần, chuyên tâm, bền bỉ, nỗ lực.",
  "dn33:2.1.94": "Đây là sự trói buộc thứ năm của tâm.",
  "dn33:2.1.95": "Năm căn là—",
  "dn33:2.1.96": "nhãn căn, nhĩ căn, tỷ căn, thiệt căn, thân căn.",
  "dn33:2.1.97": "Lại có năm căn khác—",
  "dn33:2.1.98": "lạc căn, khổ căn, hỷ căn, ưu căn, xả căn.",
  "dn33:2.1.99": "Lại có năm căn khác—",
  "dn33:2.1.100": "tín căn, tinh tấn căn, niệm căn, định căn, tuệ căn.",
  "dn33:2.1.101": "Năm giới vực đưa đến thoát ra.",
  "dn33:2.1.102": "Ở đây, này các hiền giả, khi vị tỳ-kheo tác ý đến dục, tâm không lao vào dục, không trong sáng, không đứng vững, không giải thoát.",
  "dn33:2.1.103": "Nhưng khi vị ấy tác ý đến xuất ly, tâm lao vào xuất ly, trở nên trong sáng, đứng vững, giải thoát.",
  "dn33:2.1.104": "Tâm ấy được hướng đúng, được tu tập tốt, được an lập vững, được giải thoát khéo, không còn dính mắc với dục.",
  "dn33:2.1.105": "Và những lậu hoặc, bức bách, nóng bức nào sinh khởi do duyên dục, vị ấy đã thoát khỏi chúng, vị ấy không còn cảm thọ cảm giác ấy nữa.",
  "dn33:2.1.106": "Đây được gọi là sự thoát ra khỏi dục.",
  "dn33:2.1.107": "Lại nữa, này các hiền giả, khi vị tỳ-kheo tác ý đến sân, tâm không lao vào sân, không trong sáng, không đứng vững, không giải thoát.",
  "dn33:2.1.108": "Nhưng khi vị ấy tác ý đến không sân, tâm lao vào không sân, trở nên trong sáng, đứng vững, giải thoát.",
  "dn33:2.1.109": "Tâm ấy được hướng đúng, được tu tập tốt, được an lập vững, được giải thoát khéo, không còn dính mắc với sân.",
  "dn33:2.1.110": "Và những lậu hoặc, bức bách, nóng bức nào sinh khởi do duyên sân, vị ấy đã thoát khỏi chúng, vị ấy không còn cảm thọ cảm giác ấy nữa.",
  "dn33:2.1.111": "Đây được gọi là sự thoát ra khỏi sân.",
  "dn33:2.1.112": "Lại nữa, này các hiền giả, khi vị tỳ-kheo tác ý đến hại, tâm không lao vào sự hại, không trong sáng, không đứng vững, không giải thoát.",
  "dn33:2.1.113": "Nhưng khi vị ấy tác ý đến không hại, tâm lao vào không hại, trở nên trong sáng, đứng vững, giải thoát.",
  "dn33:2.1.114": "Tâm ấy được hướng đúng, được tu tập tốt, được an lập vững, được giải thoát khéo, không còn dính mắc với sự hại.",
  "dn33:2.1.115": "Và những lậu hoặc, bức bách, nóng bức nào sinh khởi do duyên sự hại, vị ấy đã thoát khỏi chúng, vị ấy không còn cảm thọ cảm giác ấy nữa.",
  "dn33:2.1.116": "Đây được gọi là sự thoát ra khỏi sự hại.",
  "dn33:2.1.117": "Lại nữa, này các hiền giả, khi vị tỳ-kheo tác ý đến sắc, tâm không lao vào các sắc, không trong sáng, không đứng vững, không giải thoát.",
  "dn33:2.1.118": "Nhưng khi vị ấy tác ý đến vô sắc, tâm lao vào vô sắc, trở nên trong sáng, đứng vững, giải thoát.",
  "dn33:2.1.119": "Tâm ấy được hướng đúng, được tu tập tốt, được an lập vững, được giải thoát khéo, không còn dính mắc với sắc.",
  "dn33:2.1.120": "Và những lậu hoặc, bức bách, nóng bức nào sinh khởi do duyên sắc, vị ấy đã thoát khỏi chúng, vị ấy không còn cảm thọ cảm giác ấy nữa.",
  "dn33:2.1.121": "Đây được gọi là sự thoát ra khỏi sắc.",
  "dn33:2.1.122": "Lại nữa, này các hiền giả, khi vị tỳ-kheo tác ý đến thân kiến, tâm không lao vào thân kiến, không trong sáng, không đứng vững, không giải thoát.",
  "dn33:2.1.123": "Nhưng khi vị ấy tác ý đến sự diệt của thân kiến, tâm lao vào sự diệt của thân kiến, trở nên trong sáng, đứng vững, giải thoát.",
  "dn33:2.1.124": "Tâm ấy được hướng đúng, được tu tập tốt, được an lập vững, được giải thoát khéo, không còn dính mắc với thân kiến.",
  "dn33:2.1.125": "Và những lậu hoặc, bức bách, nóng bức nào sinh khởi do duyên thân kiến, vị ấy đã thoát khỏi chúng, vị ấy không còn cảm thọ cảm giác ấy nữa.",
  "dn33:2.1.126": "Đây được gọi là sự thoát ra khỏi thân kiến.",
  "dn33:2.1.127": "Năm chỗ mở ra giải thoát.",
  "dn33:2.1.128": "Ở đây, này các hiền giả, bậc Đạo sư thuyết pháp cho vị tỳ-kheo, hoặc một vị đồng phạm hạnh đáng kính nào đó thuyết pháp.",
  "dn33:2.1.129": "Này các hiền giả, khi nào bậc Đạo sư thuyết pháp cho vị tỳ-kheo, hoặc một vị đồng phạm hạnh đáng kính nào đó thuyết pháp, thì khi ấy vị ấy cảm nhận được ý nghĩa trong pháp ấy và cảm nhận được pháp ấy.",
  "dn33:2.1.130": "Khi cảm nhận được ý nghĩa và cảm nhận được pháp, niềm vui sinh khởi nơi vị ấy; do có niềm vui, hỷ sinh khởi; tâm có hỷ thì thân được lắng dịu; thân lắng dịu thì cảm thấy an lạc; người an lạc thì tâm được định.",
  "dn33:2.1.131": "Đây là chỗ mở ra giải thoát thứ nhất.",
  "dn33:2.1.132": "Lại nữa, này các hiền giả, không phải chỉ có bậc Đạo sư hay một vị đồng phạm hạnh đáng kính nào đó thuyết pháp cho vị tỳ-kheo, mà vị ấy còn đem pháp đã nghe, đã học, giảng rộng cho người khác …",
  "dn33:2.1.133": "mà vị ấy còn tụng đọc rộng rãi pháp đã nghe, đã học …",
  "dn33:2.1.134": "mà vị ấy còn suy tầm, quán xét, chú tâm xem xét pháp đã nghe, đã học …",
  "dn33:2.1.135": "mà vị ấy còn nắm giữ khéo một đề mục định nào đó, khéo tác ý, khéo duy trì, khéo thấu suốt bằng trí tuệ.",
  "dn33:2.1.136": "Này các hiền giả, khi nào vị tỳ-kheo nắm giữ khéo một đề mục định nào đó, khéo tác ý, khéo duy trì, khéo thấu suốt bằng trí tuệ, thì khi ấy vị ấy cảm nhận được ý nghĩa trong pháp ấy và cảm nhận được pháp ấy.",
  "dn33:2.1.137": "Khi cảm nhận được ý nghĩa và cảm nhận được pháp, niềm vui sinh khởi nơi vị ấy; do có niềm vui, hỷ sinh khởi; tâm có hỷ thì thân được lắng dịu; thân lắng dịu thì cảm thấy an lạc; người an lạc thì tâm được định.",
  "dn33:2.1.138": "Đây là nền tảng giải thoát thứ năm.",
  "dn33:2.1.139": "Năm tưởng làm chín muồi sự giải thoát—",
  "dn33:2.1.140": "tưởng vô thường, tưởng khổ trong cái vô thường, tưởng không có cái tôi trong cái khổ, tưởng từ bỏ, tưởng phai nhạt.",
  "dn33:2.1.141": "Này các hiền giả, năm pháp này đã được Thế Tôn, bậc biết, bậc thấy, bậc A-la-hán, bậc tự mình giác ngộ trọn vẹn, khéo giảng dạy;",
  "dn33:2.1.142": "ở đây tất cả chúng ta đều phải cùng nhau tụng đọc … vì lợi ích, vì an vui cho chư thiên và loài người.",
  "dn33:2.2.0": "6. Sáu pháp",
  "dn33:2.2.1": "Này các hiền giả, có sáu pháp đã được Thế Tôn, bậc biết, bậc thấy, bậc A-la-hán, bậc tự mình giác ngộ trọn vẹn, khéo giảng dạy;",
  "dn33:2.2.2": "ở đây tất cả chúng ta đều phải cùng nhau tụng đọc … vì lợi ích, vì an vui cho chư thiên và loài người.",
  "dn33:2.2.3": "Sáu pháp ấy là gì?",
  "dn33:2.2.4": "Sáu xứ bên trong—",
  "dn33:2.2.5": "xứ mắt, xứ tai, xứ mũi, xứ lưỡi, xứ thân, xứ ý.",
  "dn33:2.2.6": "Sáu xứ bên ngoài—",
  "dn33:2.2.7": "xứ sắc, xứ tiếng, xứ mùi, xứ vị, xứ chạm xúc, xứ pháp.",
  "dn33:2.2.8": "Sáu nhóm thức—",
  "dn33:2.2.9": "nhãn thức, nhĩ thức, tỷ thức, thiệt thức, thân thức, ý thức.",
  "dn33:2.2.10": "Sáu nhóm xúc—",
  "dn33:2.2.11": "xúc do mắt, xúc do tai, xúc do mũi, xúc do lưỡi, xúc do thân, xúc do ý.",
  "dn33:2.2.12": "Sáu nhóm cảm thọ—",
  "dn33:2.2.13": "cảm thọ sinh từ xúc nơi mắt, cảm thọ sinh từ xúc nơi tai, cảm thọ sinh từ xúc nơi mũi, cảm thọ sinh từ xúc nơi lưỡi, cảm thọ sinh từ xúc nơi thân, cảm thọ sinh từ xúc nơi ý.",
  "dn33:2.2.14": "Sáu nhóm tưởng—",
  "dn33:2.2.15": "tưởng về sắc, tưởng về tiếng, tưởng về mùi, tưởng về vị, tưởng về chạm xúc, tưởng về pháp.",
  "dn33:2.2.16": "Sáu nhóm tác ý—",
  "dn33:2.2.17": "tác ý về sắc, tác ý về tiếng, tác ý về mùi, tác ý về vị, tác ý về chạm xúc, tác ý về pháp.",
  "dn33:2.2.18": "Sáu nhóm ái—",
  "dn33:2.2.19": "ái đối với sắc, ái đối với tiếng, ái đối với mùi, ái đối với vị, ái đối với chạm xúc, ái đối với pháp.",
  "dn33:2.2.20": "Sáu điều không kính trọng.",
  "dn33:2.2.21": "Ở đây, này các hiền giả, vị tỳ-kheo sống không kính trọng, không nể trọng bậc Đạo sư; sống không kính trọng, không nể trọng Pháp; sống không kính trọng, không nể trọng Tăng; sống không kính trọng, không nể trọng sự học tập; sống không kính trọng, không nể trọng sự tinh cần; sống không kính trọng, không nể trọng sự tiếp đón.",
  "dn33:2.2.22": "Sáu điều kính trọng.",
  "dn33:2.2.23": "Ở đây, này các hiền giả, vị tỳ-kheo sống có kính trọng, có nể trọng bậc Đạo sư; sống có kính trọng, có nể trọng Pháp; sống có kính trọng, có nể trọng Tăng; sống có kính trọng, có nể trọng sự học tập; sống có kính trọng, có nể trọng sự tinh cần; sống có kính trọng, có nể trọng sự tiếp đón.",
  "dn33:2.2.24": "Sáu cách hướng tâm đến niềm vui.",
  "dn33:2.2.25": "Do mắt thấy sắc, vị ấy hướng tâm đến sắc làm chỗ phát sinh niềm vui;",
  "dn33:2.2.26": "do tai nghe tiếng …",
  "dn33:2.2.27": "do mũi ngửi mùi …",
  "dn33:2.2.28": "do lưỡi nếm vị …",
  "dn33:2.2.29": "do thân chạm xúc.",
  "dn33:2.2.30": "Do ý nhận biết pháp, vị ấy hướng tâm đến pháp làm chỗ phát sinh niềm vui.",
  "dn33:2.2.31": "Sáu cách hướng tâm đến nỗi buồn.",
  "dn33:2.2.32": "Do mắt thấy sắc, vị ấy hướng tâm đến sắc làm chỗ phát sinh nỗi buồn …",
  "dn33:2.2.33": "do ý nhận biết pháp, vị ấy hướng tâm đến pháp làm chỗ phát sinh nỗi buồn.",
  "dn33:2.2.34": "Sáu cách hướng tâm đến xả.",
  "dn33:2.2.35": "Do mắt thấy sắc, vị ấy hướng tâm đến sắc làm chỗ phát sinh xả …",
  "dn33:2.2.36": "do ý nhận biết pháp, vị ấy hướng tâm đến pháp làm chỗ phát sinh xả.",
  "dn33:2.2.37": "Sáu pháp đáng ghi nhớ.",
  "dn33:2.2.38": "Ở đây, này các hiền giả, nơi vị tỳ-kheo có thân hành từ ái đối với các bạn đồng tu, cả trước mặt lẫn sau lưng.",
  "dn33:2.2.39": "Pháp này cũng là pháp đáng ghi nhớ, tạo nên thương mến, tạo nên kính trọng, đưa đến đoàn kết, không tranh cãi, hòa hợp, đồng lòng.",
  "dn33:2.2.40": "Lại nữa, này các hiền giả, nơi vị tỳ-kheo có lời nói từ ái đối với các bạn đồng tu, cả trước mặt lẫn sau lưng.",
  "dn33:2.2.41": "Pháp này cũng là pháp đáng ghi nhớ … đưa đến đồng lòng.",
  "dn33:2.2.42": "Lại nữa, này các hiền giả, nơi vị tỳ-kheo có ý nghĩ từ ái đối với các bạn đồng tu, cả trước mặt lẫn sau lưng.",
  "dn33:2.2.43": "Pháp này cũng là pháp đáng ghi nhớ … đưa đến đồng lòng.",
  "dn33:2.2.44": "Lại nữa, này các hiền giả, vị tỳ-kheo đối với những vật nhận được đúng pháp, có được đúng pháp, cho đến chỉ là chút ít trong bát, cũng không dùng riêng, mà cùng chia sẻ chung với các bạn đồng tu có giới hạnh.",
  "dn33:2.2.45": "Pháp này cũng là pháp đáng ghi nhớ … đưa đến hòa hợp, đồng nhất.",
  "dn33:2.2.46": "Lại nữa, này các hiền giả, vị tỳ kheo sống cùng chung giới với các bạn đồng tu, cả trước mặt lẫn sau lưng, trong những giới không sứt mẻ, không rách vỡ, không lốm đốm, không tì vết, đem lại tự do, được người có trí khen ngợi, không bị chấp thủ, đưa đến định.",
  "dn33:2.2.47": "Pháp này cũng là pháp đáng ghi nhớ … đưa đến hòa hợp, đồng nhất.",
  "dn33:2.2.48": "Lại nữa, này các hiền giả, vị tỳ kheo sống cùng chung cái thấy với các bạn đồng tu, cả trước mặt lẫn sau lưng, với cái thấy thuộc bậc thánh, đưa ra khỏi, dẫn người thực hành theo đó đến chỗ dứt khổ một cách đúng đắn.",
  "dn33:2.2.49": "Pháp này cũng là pháp đáng ghi nhớ, làm cho thương mến, làm cho kính trọng, đưa đến đoàn kết, không tranh cãi, hòa hợp, đồng nhất.",
  "dn33:2.2.50": "Có sáu gốc rễ của tranh cãi.",
  "dn33:2.2.51": "Ở đây, này các hiền giả, vị tỳ kheo hay giận dữ, ôm lòng hờn oán.",
  "dn33:2.2.52": "Này các hiền giả, vị tỳ kheo nào hay giận dữ, ôm lòng hờn oán, vị ấy sống không kính trọng, không nể vì bậc Đạo sư; cũng không kính trọng, không nể vì Pháp; cũng không kính trọng, không nể vì Tăng; và cũng không thực hành đầy đủ sự học.",
  "dn33:2.2.53": "Này các hiền giả, vị tỳ kheo nào sống không kính trọng, không nể vì bậc Đạo sư, không kính trọng, không nể vì Pháp, không kính trọng, không nể vì Tăng, không thực hành đầy đủ sự học, vị ấy gây ra tranh cãi trong Tăng. Tranh cãi ấy đưa đến bất lợi, không an vui, tổn hại, không lợi ích, khổ đau cho nhiều người, cho chư thiên và loài người.",
  "dn33:2.2.54": "Này các hiền giả, nếu các vị thấy gốc rễ tranh cãi như vậy ở trong mình hay ở bên ngoài, thì ở đó các vị phải cố gắng để dứt bỏ chính gốc rễ tranh cãi xấu ác ấy.",
  "dn33:2.2.55": "Này các hiền giả, nếu các vị không thấy gốc rễ tranh cãi như vậy ở trong mình hay ở bên ngoài, thì ở đó các vị phải thực hành để gốc rễ tranh cãi xấu ác ấy không khởi lên về sau.",
  "dn33:2.2.56": "Như vậy là sự dứt bỏ gốc rễ tranh cãi xấu ác ấy. Như vậy là gốc rễ tranh cãi xấu ác ấy không khởi lên về sau.",
  "dn33:2.2.57": "Lại nữa, này các hiền giả, vị tỳ kheo hay khinh chê, hay chống đối …",
  "dn33:2.2.58": "hay ganh tị, hay bỏn sẻn …",
  "dn33:2.2.59": "hay giả dối, hay lừa gạt …",
  "dn33:2.2.60": "ham muốn xấu ác, có tà kiến …",
  "dn33:2.2.61": "chấp chặt cái thấy của mình, nắm giữ cứng ngắc, khó buông bỏ …",
  "dn33:2.2.62": "Này các hiền giả, vị tỳ kheo nào chấp chặt cái thấy của mình, nắm giữ cứng ngắc, khó buông bỏ, vị ấy sống không kính trọng, không nể vì bậc Đạo sư; cũng không kính trọng, không nể vì Pháp; cũng không kính trọng, không nể vì Tăng; và cũng không thực hành đầy đủ sự học.",
  "dn33:2.2.63": "Này các hiền giả, vị tỳ kheo nào sống không kính trọng, không nể vì bậc Đạo sư, không kính trọng, không nể vì Pháp, không kính trọng, không nể vì Tăng, không thực hành đầy đủ sự học, vị ấy gây ra tranh cãi trong Tăng. Tranh cãi ấy đưa đến bất lợi, không an vui, tổn hại, không lợi ích, khổ đau cho nhiều người, cho chư thiên và loài người.",
  "dn33:2.2.64": "Này các hiền giả, nếu các vị thấy gốc rễ tranh cãi như vậy ở trong mình hay ở bên ngoài, thì ở đó các vị phải cố gắng để dứt bỏ chính gốc rễ tranh cãi xấu ác ấy.",
  "dn33:2.2.65": "Này các hiền giả, nếu các vị không thấy gốc rễ tranh cãi như vậy ở trong mình hay ở bên ngoài, thì ở đó các vị phải thực hành để gốc rễ tranh cãi xấu ác ấy không khởi lên về sau.",
  "dn33:2.2.66": "Như vậy là sự dứt bỏ gốc rễ tranh cãi xấu ác ấy. Như vậy là gốc rễ tranh cãi xấu ác ấy không khởi lên về sau.",
  "dn33:2.2.67": "Có sáu giới:",
  "dn33:2.2.68": "giới đất, giới nước, giới lửa, giới gió, giới hư không, giới thức.",
  "dn33:2.2.69": "Có sáu giới đưa đến thoát ra.",
  "dn33:2.2.70": "Ở đây, này các hiền giả, vị tỳ kheo có thể nói như vầy:",
  "dn33:2.2.71": "‘Tâm giải thoát do lòng từ của tôi đã được tu tập, làm cho nhiều lên, lấy làm cỗ xe, lấy làm nền tảng, làm cho vững chắc, quen dùng, khéo khởi lên,",
  "dn33:2.2.72": "thế mà sân hận vẫn chiếm ngự tâm tôi.’",
  "dn33:2.2.73": "Vị ấy cần được nói rằng: ‘Chớ có nói vậy, thưa hiền giả, chớ nói như thế, chớ vu cho Thế Tôn; vu cho Thế Tôn như vậy là không tốt, vì Thế Tôn không nói như thế.",
  "dn33:2.2.74": "Này các hiền giả, điều ấy không thể có, không có chỗ xảy ra, rằng tâm giải thoát do lòng từ đã được tu tập, làm cho nhiều lên, lấy làm cỗ xe, lấy làm nền tảng, làm cho vững chắc, quen dùng, khéo khởi lên,",
  "dn33:2.2.75": "mà sân hận vẫn chiếm ngự tâm người ấy; chuyện ấy không thể có.",
  "dn33:2.2.76": "Vì đây là lối thoát khỏi sân hận, này các hiền giả, tức là tâm giải thoát do lòng từ.’",
  "dn33:2.2.77": "Ở đây nữa, này các hiền giả, vị tỳ kheo có thể nói như vầy:",
  "dn33:2.2.78": "‘Tâm giải thoát do lòng bi của tôi đã được tu tập, làm cho nhiều lên, lấy làm cỗ xe, lấy làm nền tảng, làm cho vững chắc, quen dùng, khéo khởi lên.",
  "dn33:2.2.79": "Thế mà ý làm hại vẫn chiếm ngự tâm tôi.’",
  "dn33:2.2.80": "Vị ấy cần được nói rằng: ‘Chớ có nói vậy, thưa hiền giả, chớ nói như thế, chớ vu cho Thế Tôn; vu cho Thế Tôn như vậy là không tốt, vì Thế Tôn không nói như thế.",
  "dn33:2.2.81": "Này các hiền giả, điều ấy không thể có, không có chỗ xảy ra, rằng tâm giải thoát do lòng bi đã được tu tập, làm cho nhiều lên, lấy làm cỗ xe, lấy làm nền tảng, làm cho vững chắc, quen dùng, khéo khởi lên,",
  "dn33:2.2.82": "mà ý làm hại vẫn chiếm ngự tâm người ấy; chuyện ấy không thể có.",
  "dn33:2.2.83": "Vì đây là lối thoát khỏi ý làm hại, này các hiền giả, tức là tâm giải thoát do lòng bi.’",
  "dn33:2.2.84": "Ở đây nữa, này các hiền giả, vị tỳ kheo có thể nói như vầy:",
  "dn33:2.2.85": "‘Tâm giải thoát do lòng vui theo của tôi đã được tu tập, làm cho nhiều lên, lấy làm cỗ xe, lấy làm nền tảng, làm cho vững chắc, quen dùng, khéo khởi lên.",
  "dn33:2.2.86": "Thế mà sự không vui vẫn chiếm ngự tâm tôi.’",
  "dn33:2.2.87": "Vị ấy cần được nói rằng: ‘Chớ có nói vậy, thưa hiền giả, chớ nói như thế, chớ vu cho Thế Tôn; vu cho Thế Tôn như vậy là không tốt, vì Thế Tôn không nói như thế.",
  "dn33:2.2.88": "Này các hiền giả, điều ấy không thể có, không có chỗ xảy ra, rằng tâm giải thoát do lòng vui theo đã được tu tập, làm cho nhiều lên, lấy làm cỗ xe, lấy làm nền tảng, làm cho vững chắc, quen dùng, khéo khởi lên,",
  "dn33:2.2.89": "mà sự không vui vẫn chiếm ngự tâm người ấy; chuyện ấy không thể có.",
  "dn33:2.2.90": "Vì đây là lối thoát khỏi sự không vui, này các hiền giả, tức là tâm giải thoát do lòng vui theo.’",
  "dn33:2.2.91": "Ở đây nữa, này các hiền giả, vị tỳ kheo có thể nói như vầy:",
  "dn33:2.2.92": "‘Tâm giải thoát do xả của tôi đã được tu tập, làm cho nhiều lên, lấy làm cỗ xe, lấy làm nền tảng, làm cho vững chắc, quen dùng, khéo khởi lên.",
  "dn33:2.2.93": "Thế mà tham ái vẫn chiếm ngự tâm tôi.’",
  "dn33:2.2.94": "Vị ấy cần được nói rằng: ‘Chớ có nói vậy, thưa hiền giả, chớ nói như thế, chớ vu cho Thế Tôn; vu cho Thế Tôn như vậy là không tốt, vì Thế Tôn không nói như thế.’",
  "dn33:2.2.95": "Này hiền giả, điều này không thể có, không có khả năng xảy ra, rằng khi tâm giải thoát do xả đã được tu tập, làm cho sung mãn, làm thành cỗ xe, lấy làm nền tảng, thiết lập vững chắc, quen thuộc, khéo khởi lên, ",
  "dn33:2.2.96": "mà tham ái lại chiếm ngự tâm người ấy và đứng vững; chuyện ấy không thể có.",
  "dn33:2.2.97": "Vì này hiền giả, đây là lối thoát khỏi tham ái, tức là tâm giải thoát do xả.",
  "dn33:2.2.98": "Ở đây, này hiền giả, nếu có vị tỳ kheo nói như vầy:",
  "dn33:2.2.99": "‘Tâm giải thoát vô tướng của tôi đã được tu tập, làm cho sung mãn, làm thành cỗ xe, lấy làm nền tảng, thiết lập vững chắc, quen thuộc, khéo khởi lên.",
  "dn33:2.2.100": "Nhưng thức của tôi vẫn chạy theo tướng.’",
  "dn33:2.2.101": "Vị ấy cần được nói rằng: ‘Chớ có nói như vậy, thưa hiền giả, chớ vu cho Thế Tôn; vu cho Thế Tôn như vậy là không đúng, vì Thế Tôn không nói như vậy.",
  "dn33:2.2.102": "Này hiền giả, điều này không thể có, không có khả năng xảy ra, rằng khi tâm giải thoát vô tướng đã được tu tập, làm cho sung mãn, làm thành cỗ xe, lấy làm nền tảng, thiết lập vững chắc, quen thuộc, khéo khởi lên,",
  "dn33:2.2.103": "mà thức của người ấy lại chạy theo tướng; chuyện ấy không thể có.",
  "dn33:2.2.104": "Vì này hiền giả, đây là lối thoát khỏi mọi tướng, tức là tâm giải thoát vô tướng.’",
  "dn33:2.2.105": "Ở đây, này hiền giả, nếu có vị tỳ kheo nói như vầy:",
  "dn33:2.2.106": "‘Cái nghĩ “ta là” nơi tôi đã hết, tôi không còn thấy “ta là cái này”,",
  "dn33:2.2.107": "nhưng tâm tôi vẫn bị mũi tên nghi ngờ, phân vân chiếm ngự.’",
  "dn33:2.2.108": "Vị ấy cần được nói rằng: ‘Chớ có nói như vậy, thưa hiền giả, chớ vu cho Thế Tôn; vu cho Thế Tôn như vậy là không đúng, vì Thế Tôn không nói như vậy.",
  "dn33:2.2.109": "Này hiền giả, điều này không thể có, không có khả năng xảy ra, rằng khi cái nghĩ “ta là” đã hết, khi không còn thấy “ta là cái này”,",
  "dn33:2.2.110": "mà tâm người ấy vẫn bị mũi tên nghi ngờ, phân vân chiếm ngự và đứng vững; chuyện ấy không thể có.",
  "dn33:2.2.111": "Vì này hiền giả, đây là lối thoát khỏi mũi tên nghi ngờ, phân vân, tức là nhổ tận gốc ngã mạn “ta là”.",
  "dn33:2.2.112": "Sáu điều không gì hơn—",
  "dn33:2.2.113": "không gì hơn về thấy, không gì hơn về nghe, không gì hơn về được, không gì hơn về học tập, không gì hơn về phụng sự, không gì hơn về nhớ nghĩ.",
  "dn33:2.2.114": "Sáu chỗ nhớ nghĩ—",
  "dn33:2.2.115": "niệm Phật, niệm Pháp, niệm Tăng, niệm giới, niệm thí, niệm chư thiên.",
  "dn33:2.2.116": "Sáu cách an trú thường xuyên.",
  "dn33:2.2.117": "Ở đây, này hiền giả, vị tỳ kheo mắt thấy sắc thì không vui cũng không buồn, sống với tâm xả, có chánh niệm, tỉnh giác.",
  "dn33:2.2.118": "Tai nghe tiếng …",
  "dn33:2.2.119": "ý nhận biết pháp thì không vui cũng không buồn, sống với tâm xả, có chánh niệm, tỉnh giác.",
  "dn33:2.2.120": "Sáu hạng sinh loại.",
  "dn33:2.2.121": "Ở đây, này hiền giả, có người sinh loại đen mà tạo nghiệp đen.",
  "dn33:2.2.122": "Ở đây nữa, này hiền giả, có người sinh loại đen mà tạo nghiệp trắng.",
  "dn33:2.2.123": "Ở đây nữa, này hiền giả, có người sinh loại đen mà chứng đạt Niết-bàn không đen không trắng.",
  "dn33:2.2.124": "Ở đây nữa, này hiền giả, có người sinh loại trắng mà tạo nghiệp trắng.",
  "dn33:2.2.125": "Ở đây nữa, này hiền giả, có người sinh loại trắng mà tạo nghiệp đen.",
  "dn33:2.2.126": "Ở đây nữa, này hiền giả, có người sinh loại trắng mà chứng đạt Niết-bàn không đen không trắng.",
  "dn33:2.2.127": "Sáu tưởng đưa đến thấu suốt—",
  "dn33:2.2.128": "tưởng vô thường, tưởng khổ trong cái vô thường, tưởng vô ngã trong cái khổ, tưởng từ bỏ, tưởng phai nhạt, tưởng diệt.",
  "dn33:2.2.129": "Này hiền giả, đó là sáu pháp đã được Thế Tôn, bậc biết, bậc thấy, bậc A-la-hán, bậc Chánh Đẳng Giác, khéo giảng dạy;",
  "dn33:2.2.130": "ở đây tất cả đều phải cùng nhau kết tập … vì lợi ích, vì an vui cho chư thiên và loài người.",
  "dn33:2.3.0": "7. Nhóm bảy",
  "dn33:2.3.1": "Này hiền giả, có bảy pháp đã được Thế Tôn, bậc biết, bậc thấy, bậc A-la-hán, bậc Chánh Đẳng Giác, khéo giảng dạy;",
  "dn33:2.3.2": "ở đây tất cả đều phải cùng nhau kết tập … vì lợi ích, vì an vui cho chư thiên và loài người.",
  "dn33:2.3.3": "Bảy pháp ấy là gì?",
  "dn33:2.3.4": "Bảy tài sản của bậc thánh—",
  "dn33:2.3.5": "tài sản là lòng tin, tài sản là giới, tài sản là biết hổ thẹn, tài sản là biết sợ điều xấu, tài sản là học nhiều, tài sản là buông xả, tài sản là trí tuệ.",
  "dn33:2.3.6": "Bảy chi phần giác ngộ—",
  "dn33:2.3.7": "chi phần giác ngộ là niệm, chi phần giác ngộ là trạch pháp, chi phần giác ngộ là tinh tấn, chi phần giác ngộ là hỷ, chi phần giác ngộ là an tịnh, chi phần giác ngộ là định, chi phần giác ngộ là xả.",
  "dn33:2.3.8": "Bảy món trợ duyên cho định—",
  "dn33:2.3.9": "chánh kiến, chánh tư duy, chánh ngữ, chánh nghiệp, chánh mạng, chánh tinh tấn, chánh niệm.",
  "dn33:2.3.10": "Bảy pháp không chân chánh—",
  "dn33:2.3.11": "ở đây, này hiền giả, vị tỳ kheo không có lòng tin, không biết hổ thẹn, không biết sợ điều xấu, học ít, biếng nhác, thất niệm, thiếu trí tuệ.",
  "dn33:2.3.12": "Bảy pháp chân chánh—",
  "dn33:2.3.13": "ở đây, này hiền giả, vị tỳ kheo có lòng tin, biết hổ thẹn, biết sợ điều xấu, học nhiều, tinh tấn được khởi lên, chánh niệm được thiết lập, có trí tuệ.",
  "dn33:2.3.14": "Bảy pháp của người tốt—",
  "dn33:2.3.15": "Này các hiền giả, ở đây vị tỳ kheo là người biết pháp, biết nghĩa, biết mình, biết chừng mực, biết thời, biết hội chúng, biết người.",
  "dn33:2.3.16": "Bảy nền tảng để nêu rõ.",
  "dn33:2.3.17": "Này các hiền giả, ở đây vị tỳ kheo có ước muốn mạnh mẽ trong việc nhận lãnh sự học, và về sau vẫn không mất lòng yêu mến đối với việc nhận lãnh sự học.",
  "dn33:2.3.18": "Có ước muốn mạnh mẽ trong việc lắng nghe pháp, và về sau vẫn không mất lòng yêu mến đối với việc lắng nghe pháp.",
  "dn33:2.3.19": "Có ước muốn mạnh mẽ trong việc dứt trừ ham muốn, và về sau vẫn không mất lòng yêu mến đối với việc dứt trừ ham muốn.",
  "dn33:2.3.20": "Có ước muốn mạnh mẽ trong việc sống riêng tĩnh lặng, và về sau vẫn không mất lòng yêu mến đối với việc sống riêng tĩnh lặng.",
  "dn33:2.3.21": "Có ước muốn mạnh mẽ trong việc khởi lên tinh tấn, và về sau vẫn không mất lòng yêu mến đối với việc khởi lên tinh tấn.",
  "dn33:2.3.22": "Có ước muốn mạnh mẽ trong việc khéo giữ chánh niệm, và về sau vẫn không mất lòng yêu mến đối với việc khéo giữ chánh niệm.",
  "dn33:2.3.23": "Có ước muốn mạnh mẽ trong việc thấu đạt chánh kiến, và về sau vẫn không mất lòng yêu mến đối với việc thấu đạt chánh kiến.",
  "dn33:2.3.24": "Bảy tưởng—",
  "dn33:2.3.25": "tưởng vô thường, tưởng vô ngã, tưởng bất tịnh, tưởng thấy sự nguy hại, tưởng từ bỏ, tưởng lìa tham, tưởng diệt.",
  "dn33:2.3.26": "Bảy sức mạnh—",
  "dn33:2.3.27": "sức mạnh của lòng tin, sức mạnh của tinh tấn, sức mạnh của hổ thẹn, sức mạnh của ghê sợ điều xấu, sức mạnh của chánh niệm, sức mạnh của định, sức mạnh của trí tuệ.",
  "dn33:2.3.28": "Bảy chỗ an trú của thức.",
  "dn33:2.3.29": "Này các hiền giả, có những chúng sinh thân khác nhau, tưởng khác nhau, như loài người, một số chư thiên và một số chúng sinh ở cõi khổ.",
  "dn33:2.3.30": "Đây là chỗ an trú thứ nhất của thức.",
  "dn33:2.3.31": "Này các hiền giả, có những chúng sinh thân khác nhau nhưng tưởng giống nhau, như chư thiên thuộc cõi Phạm thiên mới sinh lần đầu.",
  "dn33:2.3.32": "Đây là chỗ an trú thứ hai của thức.",
  "dn33:2.3.33": "Này các hiền giả, có những chúng sinh thân giống nhau nhưng tưởng khác nhau, như chư thiên cõi Quang Âm.",
  "dn33:2.3.34": "Đây là chỗ an trú thứ ba của thức.",
  "dn33:2.3.35": "Này các hiền giả, có những chúng sinh thân giống nhau và tưởng cũng giống nhau, như chư thiên cõi Biến Tịnh.",
  "dn33:2.3.36": "Đây là chỗ an trú thứ tư của thức.",
  "dn33:2.3.37": "Này các hiền giả, có những chúng sinh vượt qua hoàn toàn các tưởng về sắc, do các tưởng đối kháng đã lắng xuống, không tác ý đến các tưởng sai khác, nghĩ rằng: ‘Hư không là vô biên’, và đi đến cõi vô biên hư không.",
  "dn33:2.3.38": "Đây là chỗ an trú thứ năm của thức.",
  "dn33:2.3.39": "Này các hiền giả, có những chúng sinh vượt qua hoàn toàn cõi vô biên hư không, nghĩ rằng: ‘Thức là vô biên’, và đi đến cõi vô biên thức.",
  "dn33:2.3.40": "Đây là chỗ an trú thứ sáu của thức.",
  "dn33:2.3.41": "Này các hiền giả, có những chúng sinh vượt qua hoàn toàn cõi vô biên thức, nghĩ rằng: ‘Không có gì cả’, và đi đến cõi không có gì cả.",
  "dn33:2.3.42": "Đây là chỗ an trú thứ bảy của thức.",
  "dn33:2.3.43": "Bảy hạng người xứng đáng được cúng dường—",
  "dn33:2.3.44": "người giải thoát cả hai phần, người giải thoát nhờ trí tuệ, người thân chứng, người đạt được chánh kiến, người giải thoát nhờ lòng tin, người đi theo pháp, người đi theo lòng tin.",
  "dn33:2.3.45": "Bảy khuynh hướng ngầm—",
  "dn33:2.3.46": "khuynh hướng ngầm của tham dục, khuynh hướng ngầm của sân, khuynh hướng ngầm của tà kiến, khuynh hướng ngầm của nghi, khuynh hướng ngầm của ngã mạn, khuynh hướng ngầm của tham hữu, khuynh hướng ngầm của vô minh.",
  "dn33:2.3.47": "Bảy trói buộc—",
  "dn33:2.3.48": "trói buộc bởi chiều theo, trói buộc bởi chống đối, trói buộc bởi tà kiến, trói buộc bởi nghi, trói buộc bởi ngã mạn, trói buộc bởi tham hữu, trói buộc bởi vô minh.",
  "dn33:2.3.49": "Bảy cách dàn xếp tranh sự để làm lắng dịu, làm yên các tranh sự đã khởi lên—",
  "dn33:2.3.50": "phải xử trước mặt, phải xử theo chánh niệm, phải xử khi không điên loạn, phải làm theo sự nhận lỗi, theo đa số, xử người ấy là xấu hơn, phủ cỏ lên trên.",
  "dn33:2.3.51": "Này các hiền giả, đó là bảy pháp đã được Thế Tôn, bậc biết, bậc thấy, bậc A-la-hán, bậc Chánh Đẳng Giác, khéo giảng dạy.",
  "dn33:2.3.52": "Ở đây tất cả đều phải cùng nhau kết tập … vì lợi ích, vì an vui cho chư thiên và loài người.",
  "dn33:2.3.53": "Phần tụng đọc thứ hai đã xong.",
  "dn33:3.1.0": "8. Tám pháp",
  "dn33:3.1.1": "Này các hiền giả, có tám pháp đã được Thế Tôn, bậc biết, bậc thấy, bậc A-la-hán, bậc Chánh Đẳng Giác, khéo giảng dạy.",
  "dn33:3.1.2": "Ở đây tất cả đều phải cùng nhau kết tập … vì lợi ích, vì an vui cho chư thiên và loài người.",
  "dn33:3.1.3": "Tám pháp ấy là gì?",
  "dn33:3.1.4": "Tám điều sai lạc—",
  "dn33:3.1.5": "tà kiến, tà tư duy, tà ngữ, tà nghiệp, tà mạng, tà tinh tấn, tà niệm, tà định.",
  "dn33:3.1.6": "Tám điều chân chánh—",
  "dn33:3.1.7": "chánh kiến, chánh tư duy, chánh ngữ, chánh nghiệp, chánh mạng, chánh tinh tấn, chánh niệm, chánh định.",
  "dn33:3.1.8": "Tám hạng người xứng đáng được cúng dường—",
  "dn33:3.1.9": "bậc nhập lưu, người đang thực hành để chứng quả nhập lưu; bậc nhất lai, người đang thực hành để chứng quả nhất lai; bậc bất lai, người đang thực hành để chứng quả bất lai; bậc A-la-hán, người đang thực hành để chứng quả A-la-hán.",
  "dn33:3.1.10": "Tám điều làm sinh lười biếng. ",
  "dn33:3.1.11": "Này các hiền giả, ở đây một vị tỳ kheo có việc phải làm. ",
  "dn33:3.1.12": "Vị ấy nghĩ như vầy: ",
  "dn33:3.1.13": "‘Ta sẽ phải làm việc; nhưng khi làm việc thì thân ta sẽ mệt, thôi ta nằm xuống vậy.’ ",
  "dn33:3.1.14": "Vị ấy nằm xuống, không khởi lên tinh tấn để đạt điều chưa đạt, chứng điều chưa chứng, thấy rõ điều chưa thấy rõ. ",
  "dn33:3.1.15": "Đây là điều thứ nhất làm sinh lười biếng. ",
  "dn33:3.1.16": "Lại nữa, này các hiền giả, một vị tỳ kheo đã làm xong việc. ",
  "dn33:3.1.17": "Vị ấy nghĩ như vầy: ",
  "dn33:3.1.18": "‘Ta đã làm việc xong; nhưng khi làm việc thì thân ta đã mệt, thôi ta nằm xuống vậy.’ ",
  "dn33:3.1.19": "Vị ấy nằm xuống, không khởi lên tinh tấn … ",
  "dn33:3.1.20": "đây là điều thứ hai làm sinh lười biếng. ",
  "dn33:3.1.21": "Lại nữa, này các hiền giả, một vị tỳ kheo phải đi đường. ",
  "dn33:3.1.22": "Vị ấy nghĩ như vầy: ",
  "dn33:3.1.23": "‘Ta sẽ phải đi đường; nhưng khi đi đường thì thân ta sẽ mệt, thôi ta nằm xuống vậy.’ ",
  "dn33:3.1.24": "Vị ấy nằm xuống, không khởi lên tinh tấn … ",
  "dn33:3.1.25": "đây là điều thứ ba làm sinh lười biếng. ",
  "dn33:3.1.26": "Lại nữa, này các hiền giả, một vị tỳ kheo đã đi đường xong. ",
  "dn33:3.1.27": "Vị ấy nghĩ như vầy: ",
  "dn33:3.1.28": "‘Ta đã đi đường xong; nhưng khi đi đường thì thân ta đã mệt, thôi ta nằm xuống vậy.’ ",
  "dn33:3.1.29": "Vị ấy nằm xuống, không khởi lên tinh tấn … ",
  "dn33:3.1.30": "đây là điều thứ tư làm sinh lười biếng. ",
  "dn33:3.1.31": "Lại nữa, này các hiền giả, một vị tỳ kheo đi khất thực trong làng hay thị trấn, không kiếm được đủ thức ăn, dù thô hay ngon, để no bụng. ",
  "dn33:3.1.32": "Vị ấy nghĩ như vầy: ",
  "dn33:3.1.33": "‘Ta đi khất thực trong làng hay thị trấn, đã không kiếm được đủ thức ăn, dù thô hay ngon, để no bụng; thân ta vì thế mệt mỏi, không làm được gì, thôi ta nằm xuống vậy.’ ",
  "dn33:3.1.34": "Vị ấy nằm xuống, không khởi lên tinh tấn … ",
  "dn33:3.1.35": "đây là điều thứ năm làm sinh lười biếng. ",
  "dn33:3.1.36": "Lại nữa, này các hiền giả, một vị tỳ kheo đi khất thực trong làng hay thị trấn, kiếm được đủ thức ăn, dù thô hay ngon, để no bụng. ",
  "dn33:3.1.37": "Vị ấy nghĩ như vầy: ",
  "dn33:3.1.38": "‘Ta đi khất thực trong làng hay thị trấn, đã kiếm được đủ thức ăn, dù thô hay ngon, để no bụng; thân ta nặng nề, không làm được gì, như thể đầy ắp thịt, thôi ta nằm xuống vậy.’ ",
  "dn33:3.1.39": "Vị ấy nằm xuống, không khởi lên tinh tấn … ",
  "dn33:3.1.40": "đây là điều thứ sáu làm sinh lười biếng. ",
  "dn33:3.1.41": "Lại nữa, này các hiền giả, một vị tỳ kheo mắc một cơn bệnh nhẹ. ",
  "dn33:3.1.42": "Vị ấy nghĩ như vầy: ",
  "dn33:3.1.43": "‘Ta đang mắc một cơn bệnh nhẹ này; ",
  "dn33:3.1.44": "có lý do để nằm xuống, thôi ta nằm xuống vậy.’ ",
  "dn33:3.1.45": "Vị ấy nằm xuống, không khởi lên tinh tấn … ",
  "dn33:3.1.46": "đây là điều thứ bảy làm sinh lười biếng. ",
  "dn33:3.1.47": "Lại nữa, này các hiền giả, một vị tỳ kheo vừa mới khỏi bệnh, mới đứng dậy sau cơn bệnh không bao lâu. ",
  "dn33:3.1.48": "Vị ấy nghĩ như vầy: ",
  "dn33:3.1.49": "‘Ta vừa mới khỏi bệnh, mới đứng dậy sau cơn bệnh không bao lâu; thân ta yếu, không làm được gì, thôi ta nằm xuống vậy.’ ",
  "dn33:3.1.50": "Vị ấy nằm xuống, không khởi lên tinh tấn để đạt điều chưa đạt, chứng điều chưa chứng, thấy rõ điều chưa thấy rõ. ",
  "dn33:3.1.51": "Đây là điều thứ tám làm sinh lười biếng. ",
  "dn33:3.1.52": "Tám điều làm sinh tinh tấn. ",
  "dn33:3.1.53": "Này các hiền giả, ở đây một vị tỳ kheo có việc phải làm. ",
  "dn33:3.1.54": "Vị ấy nghĩ như vầy: ",
  "dn33:3.1.55": "‘Ta sẽ phải làm việc; nhưng khi đang làm việc thì không dễ để để tâm đến lời dạy của các bậc Giác Ngộ; thôi ta khởi lên tinh tấn để đạt điều chưa đạt, chứng điều chưa chứng, thấy rõ điều chưa thấy rõ.’ ",
  "dn33:3.1.56": "Vị ấy khởi lên tinh tấn để đạt điều chưa đạt, chứng điều chưa chứng, thấy rõ điều chưa thấy rõ. ",
  "dn33:3.1.57": "Đây là điều thứ nhất làm sinh tinh tấn. ",
  "dn33:3.1.58": "Lại nữa, này các hiền giả, một vị tỳ kheo đã làm xong việc. ",
  "dn33:3.1.59": "Vị ấy nghĩ như vầy: ",
  "dn33:3.1.60": "‘Ta đã làm việc cần làm, nhưng khi đang làm việc ấy, ta không thể để tâm đến lời dạy của các đức Phật. Vậy ta hãy khởi lên tinh tấn …",
  "dn33:3.1.61": "vị ấy khởi lên tinh tấn …",
  "dn33:3.1.62": "Đây là nền tảng khởi tinh tấn thứ hai.",
  "dn33:3.1.63": "Lại nữa, này các hiền giả, một vị tỳ kheo phải đi đường.",
  "dn33:3.1.64": "Vị ấy nghĩ như vầy:",
  "dn33:3.1.65": "‘Ta sẽ phải đi đường, nhưng khi đang đi đường, ta không dễ để tâm đến lời dạy của các đức Phật.",
  "dn33:3.1.66": "Vậy ta hãy khởi lên tinh tấn …",
  "dn33:3.1.67": "vị ấy khởi lên tinh tấn …",
  "dn33:3.1.68": "Đây là nền tảng khởi tinh tấn thứ ba.",
  "dn33:3.1.69": "Lại nữa, này các hiền giả, một vị tỳ kheo đã đi đường xong.",
  "dn33:3.1.70": "Vị ấy nghĩ như vầy:",
  "dn33:3.1.71": "‘Ta đã đi đường xong, nhưng khi đang đi đường, ta không thể để tâm đến lời dạy của các đức Phật. Vậy ta hãy khởi lên tinh tấn …",
  "dn33:3.1.72": "vị ấy khởi lên tinh tấn …",
  "dn33:3.1.73": "Đây là nền tảng khởi tinh tấn thứ tư.",
  "dn33:3.1.74": "Lại nữa, này các hiền giả, một vị tỳ kheo đi khất thực trong làng hay thị trấn mà không nhận được đủ phần ăn, dù thô hay ngon, cho vừa nhu cầu.",
  "dn33:3.1.75": "Vị ấy nghĩ như vầy:",
  "dn33:3.1.76": "‘Ta đi khất thực trong làng hay thị trấn mà không nhận được đủ phần ăn, dù thô hay ngon, cho vừa nhu cầu. Vì thế thân ta nhẹ nhàng, dễ dùng. Vậy ta hãy khởi lên tinh tấn …",
  "dn33:3.1.77": "vị ấy khởi lên tinh tấn …",
  "dn33:3.1.78": "Đây là nền tảng khởi tinh tấn thứ năm.",
  "dn33:3.1.79": "Lại nữa, này các hiền giả, một vị tỳ kheo đi khất thực trong làng hay thị trấn và nhận được đủ phần ăn, dù thô hay ngon, cho vừa nhu cầu.",
  "dn33:3.1.80": "Vị ấy nghĩ như vầy:",
  "dn33:3.1.81": "‘Ta đi khất thực trong làng hay thị trấn và đã nhận được đủ phần ăn, dù thô hay ngon, cho vừa nhu cầu. Vì thế thân ta khỏe mạnh, dễ dùng. Vậy ta hãy khởi lên tinh tấn …",
  "dn33:3.1.82": "vị ấy khởi lên tinh tấn …",
  "dn33:3.1.83": "Đây là nền tảng khởi tinh tấn thứ sáu.",
  "dn33:3.1.84": "Lại nữa, này các hiền giả, một vị tỳ kheo mắc một cơn bệnh nhẹ.",
  "dn33:3.1.85": "Vị ấy nghĩ như vầy:",
  "dn33:3.1.86": "‘Ta đang mắc một cơn bệnh nhẹ này, nhưng có thể bệnh ấy sẽ nặng thêm. Vậy ta hãy khởi lên tinh tấn …",
  "dn33:3.1.87": "vị ấy khởi lên tinh tấn …",
  "dn33:3.1.88": "Đây là nền tảng khởi tinh tấn thứ bảy.",
  "dn33:3.1.89": "Lại nữa, này các hiền giả, một vị tỳ kheo vừa mới khỏi bệnh, mới đứng dậy sau cơn bệnh không bao lâu.",
  "dn33:3.1.90": "Vị ấy nghĩ như vầy:",
  "dn33:3.1.91": "‘Ta vừa mới khỏi bệnh, mới đứng dậy sau cơn bệnh không bao lâu; nhưng có thể bệnh ấy sẽ trở lại. Vậy ta hãy khởi lên tinh tấn để đạt điều chưa đạt, chứng điều chưa chứng, tự mình thấy rõ điều chưa thấy rõ.’",
  "dn33:3.1.92": "Vị ấy khởi lên tinh tấn để đạt điều chưa đạt, chứng điều chưa chứng, tự mình thấy rõ điều chưa thấy rõ.",
  "dn33:3.1.93": "Đây là nền tảng khởi tinh tấn thứ tám.",
  "dn33:3.1.94": "Tám nền tảng của sự cho.",
  "dn33:3.1.95": "Cho vì nể, cho vì sợ, cho vì nghĩ rằng ‘người ấy đã cho ta’, cho vì nghĩ rằng ‘người ấy sẽ cho ta’, cho vì nghĩ rằng ‘cho là tốt’, cho vì nghĩ rằng ‘ta nấu ăn, còn những người này không nấu; ta không nên là người nấu ăn mà lại không cho những người không nấu’, cho vì nghĩ rằng ‘khi ta cho vật này, tiếng tốt đẹp về ta sẽ lan rộng’.",
  "dn33:3.1.96": "Cho để làm đẹp tâm, để làm giàu cho tâm.",
  "dn33:3.1.97": "Tám sự tái sinh do bố thí.",
  "dn33:3.1.98": "Ở đây, này các hiền giả, có người cho một vị sa môn hay bà la môn đồ ăn, thức uống, y áo, xe cộ, vòng hoa, hương thơm, đồ xoa, chỗ nằm, chỗ ở, đèn đuốc.",
  "dn33:3.1.99": "Người ấy mong cầu điều mình cho ấy.",
  "dn33:3.1.100": "Người ấy thấy một đại gia dòng chiến sĩ, hay một đại gia bà la môn, hay một đại gia cư sĩ đang được đầy đủ, hưởng thụ năm món dục.",
  "dn33:3.1.101": "Người ấy nghĩ như vầy:",
  "dn33:3.1.102": "‘Ôi, mong sao sau khi thân hoại mạng chung, ta được sinh cùng chỗ với các đại gia dòng chiến sĩ, hay các đại gia bà la môn, hay các đại gia cư sĩ ấy.’",
  "dn33:3.1.103": "Người ấy giữ tâm ấy, đặt tâm vào ấy, làm cho tâm ấy tăng trưởng. Tâm ấy của người ấy, vì hướng đến chỗ thấp và không được tu tập cao hơn, đưa đến tái sinh vào chỗ ấy.",
  "dn33:3.1.104": "Điều này, ta nói là dành cho người có giới, không phải cho người không có giới.",
  "dn33:3.1.105": "Này các hiền giả, ước nguyện của tâm nơi người có giới được thành tựu vì tâm ý trong sạch.",
  "dn33:3.1.106": "Lại nữa, này các hiền giả, ở đây có người cho một vị sa môn hay bà la môn đồ ăn, thức uống … chỗ nằm, chỗ ở, đèn đuốc.",
  "dn33:3.1.107": "Người ấy mong cầu điều mình cho ấy.",
  "dn33:3.1.108": "Người ấy được nghe rằng:",
  "dn33:3.1.109": "‘Chư thiên cõi Tứ Đại Vương sống lâu, đẹp đẽ, nhiều an vui.’",
  "dn33:3.1.110": "Người ấy nghĩ như vầy:",
  "dn33:3.1.111": "‘Mong sao sau khi thân hoại mạng chung, ta được sinh cùng với chư thiên Tứ Đại Thiên Vương.’",
  "dn33:3.1.112": "Người ấy hướng tâm đến điều ấy, đặt tâm vào điều ấy, tu tập tâm ấy. Tâm ấy của người ấy, vì hướng đến cảnh giới thấp hơn, không được tu tập cao hơn, nên đưa đến tái sinh vào nơi ấy.",
  "dn33:3.1.113": "Điều này, ta nói là dành cho người có giới, không phải cho người không có giới.",
  "dn33:3.1.114": "Này các hiền giả, sở nguyện của tâm người có giới được thành tựu vì tâm ấy trong sạch.",
  "dn33:3.1.115": "Lại nữa, này các hiền giả, ở đây có người bố thí cho sa môn hay bà la môn đồ ăn, thức uống … chỗ nằm, chỗ ở, đèn đuốc.",
  "dn33:3.1.116": "Người ấy mong cầu điều tương ứng với những gì mình cho.",
  "dn33:3.1.117": "Người ấy được nghe rằng:",
  "dn33:3.1.118": "‘Chư thiên cõi Ba Mươi Ba …",
  "dn33:3.1.119": "chư thiên cõi Dạ Ma …",
  "dn33:3.1.120": "chư thiên cõi Đâu Suất …",
  "dn33:3.1.121": "chư thiên cõi Hóa Lạc …",
  "dn33:3.1.122": "chư thiên cõi Tha Hóa Tự Tại sống lâu, đẹp đẽ, nhiều an vui.’",
  "dn33:3.1.123": "Người ấy nghĩ như vầy:",
  "dn33:3.1.124": "‘Mong sao sau khi thân hoại mạng chung, ta được sinh cùng với chư thiên cõi Tha Hóa Tự Tại.’",
  "dn33:3.1.125": "Người ấy hướng tâm đến điều ấy, đặt tâm vào điều ấy, tu tập tâm ấy. Tâm ấy của người ấy, vì hướng đến cảnh giới thấp hơn, không được tu tập cao hơn, nên đưa đến tái sinh vào nơi ấy.",
  "dn33:3.1.126": "Điều này, ta nói là dành cho người có giới, không phải cho người không có giới.",
  "dn33:3.1.127": "Này các hiền giả, sở nguyện của tâm người có giới được thành tựu vì tâm ấy trong sạch.",
  "dn33:3.1.128": "Lại nữa, này các hiền giả, ở đây có người bố thí cho sa môn hay bà la môn đồ ăn, thức uống, y áo, xe cộ, vòng hoa, hương thơm, đồ xoa bôi, chỗ nằm, chỗ ở, đèn đuốc.",
  "dn33:3.1.129": "Người ấy mong cầu điều tương ứng với những gì mình cho.",
  "dn33:3.1.130": "Người ấy được nghe rằng:",
  "dn33:3.1.131": "‘Chư thiên Phạm chúng sống lâu, đẹp đẽ, nhiều an vui.’",
  "dn33:3.1.132": "Người ấy nghĩ như vầy:",
  "dn33:3.1.133": "‘Mong sao sau khi thân hoại mạng chung, ta được sinh cùng với chư thiên Phạm chúng.’",
  "dn33:3.1.134": "Người ấy hướng tâm đến điều ấy, đặt tâm vào điều ấy, tu tập tâm ấy. Tâm ấy của người ấy, vì hướng đến cảnh giới thấp hơn, không được tu tập cao hơn, nên đưa đến tái sinh vào nơi ấy.",
  "dn33:3.1.135": "Điều này, ta nói là dành cho người có giới, không phải cho người không có giới;",
  "dn33:3.1.136": "dành cho người đã lìa tham, không phải cho người còn tham.",
  "dn33:3.1.137": "Này các hiền giả, sở nguyện của tâm người có giới được thành tựu vì đã lìa tham.",
  "dn33:3.1.138": "Tám hội chúng là—",
  "dn33:3.1.139": "hội chúng vua chúa, hội chúng bà la môn, hội chúng gia chủ, hội chúng sa môn, hội chúng chư thiên Tứ Đại Thiên Vương, hội chúng chư thiên cõi Ba Mươi Ba, hội chúng Ma vương, hội chúng Phạm thiên.",
  "dn33:3.1.140": "Tám pháp của đời là—",
  "dn33:3.1.141": "được lợi và mất lợi, được tiếng tốt và tiếng xấu, bị chê và được khen, vui và khổ.",
  "dn33:3.1.142": "Tám cảnh thắng tri.",
  "dn33:3.1.143": "Có người còn nhận biết sắc ở trong, thấy các sắc ở ngoài, nhỏ, đẹp hay xấu, và nghĩ: ‘Ta biết, ta thấy sau khi vượt qua chúng.’",
  "dn33:3.1.144": "Đây là cảnh thắng tri thứ nhất.",
  "dn33:3.1.145": "Có người còn nhận biết sắc ở trong, thấy các sắc ở ngoài, vô lượng, đẹp hay xấu, và nghĩ: ‘Ta biết, ta thấy sau khi vượt qua chúng.’",
  "dn33:3.1.146": "Người ấy có nhận thức như vậy.",
  "dn33:3.1.147": "Đây là cảnh thắng tri thứ hai.",
  "dn33:3.1.148": "Có người không còn nhận biết sắc ở trong, thấy các sắc ở ngoài, nhỏ, đẹp hay xấu, và nghĩ: ‘Ta biết, ta thấy sau khi vượt qua chúng.’",
  "dn33:3.1.149": "Đây là cảnh thắng tri thứ ba.",
  "dn33:3.1.150": "Có người không còn nhận biết sắc ở trong, thấy các sắc ở ngoài, vô lượng, đẹp hay xấu, và nghĩ: ‘Ta biết, ta thấy sau khi vượt qua chúng.’",
  "dn33:3.1.151": "Đây là cảnh thắng tri thứ tư.",
  "dn33:3.1.152": "Có người không còn nhận biết sắc ở trong, thấy các sắc ở ngoài màu xanh, xanh màu, hiện ra màu xanh, ánh lên màu xanh.",
  "dn33:3.1.153": "Ví như hoa lanh màu xanh, xanh màu, hiện ra màu xanh, ánh lên màu xanh; hay như tấm vải Ba-la-nại được dệt láng đều cả hai mặt, màu xanh, xanh màu, hiện ra màu xanh, ánh lên màu xanh;",
  "dn33:3.1.154": "cũng vậy, có người không còn nhận biết sắc ở trong, thấy các sắc ở ngoài màu xanh, xanh màu, hiện ra màu xanh, ánh lên màu xanh, và nghĩ: ‘Ta biết, ta thấy sau khi vượt qua chúng.’",
  "dn33:3.1.155": "Đây là cảnh thắng tri thứ năm.",
  "dn33:3.1.156": "Có người không còn nhận biết sắc ở trong, thấy các sắc ở ngoài màu vàng, vàng màu, hiện ra màu vàng, ánh lên màu vàng.",
  "dn33:3.1.157": "Ví như hoa kim anh màu vàng, vàng màu, hiện ra màu vàng, ánh lên màu vàng; hay như tấm vải Ba-la-nại được dệt láng đều cả hai mặt, màu vàng, vàng màu, hiện ra màu vàng, ánh lên màu vàng;",
  "dn33:3.1.158": "cũng vậy, có người không còn nhận biết sắc ở trong, thấy các sắc ở ngoài màu vàng, vàng màu, hiện ra màu vàng, ánh lên màu vàng, và nghĩ: ‘Ta biết, ta thấy sau khi vượt qua chúng.’",
  "dn33:3.1.159": "Đây là cảnh thắng tri thứ sáu.",
  "dn33:3.1.160": "Không nhận biết sắc ở bên trong, vị ấy thấy các sắc ở bên ngoài màu đỏ, có màu đỏ, hiện ra màu đỏ, chiếu sáng màu đỏ.",
  "dn33:3.1.161": "Ví như hoa bandhujīvaka màu đỏ, có màu đỏ, hiện ra màu đỏ, chiếu sáng màu đỏ; hay như tấm vải xứ Bārāṇasī được chải láng cả hai mặt, màu đỏ, có màu đỏ, hiện ra màu đỏ, chiếu sáng màu đỏ;",
  "dn33:3.1.162": "cũng vậy, không nhận biết sắc ở bên trong, vị ấy thấy các sắc ở bên ngoài màu đỏ, có màu đỏ, hiện ra màu đỏ, chiếu sáng màu đỏ, vị ấy nghĩ: ‘Ta biết, ta thấy sau khi vượt thắng chúng.’",
  "dn33:3.1.163": "Đây là cảnh giới thắng tri thứ bảy.",
  "dn33:3.1.164": "Không nhận biết sắc ở bên trong, vị ấy thấy các sắc ở bên ngoài màu trắng, có màu trắng, hiện ra màu trắng, chiếu sáng màu trắng.",
  "dn33:3.1.165": "Ví như sao mai màu trắng, có màu trắng, hiện ra màu trắng, chiếu sáng màu trắng; hay như tấm vải xứ Bārāṇasī được chải láng cả hai mặt, màu trắng, có màu trắng, hiện ra màu trắng, chiếu sáng màu trắng;",
  "dn33:3.1.166": "cũng vậy, không nhận biết sắc ở bên trong, vị ấy thấy các sắc ở bên ngoài màu trắng, có màu trắng, hiện ra màu trắng, chiếu sáng màu trắng, vị ấy nghĩ: ‘Ta biết, ta thấy sau khi vượt thắng chúng.’",
  "dn33:3.1.167": "Đây là cảnh giới thắng tri thứ tám.",
  "dn33:3.1.168": "Tám giải thoát.",
  "dn33:3.1.169": "Có sắc, vị ấy thấy các sắc.",
  "dn33:3.1.170": "Đây là giải thoát thứ nhất.",
  "dn33:3.1.171": "Không nhận biết sắc ở bên trong, vị ấy thấy các sắc ở bên ngoài.",
  "dn33:3.1.172": "Đây là giải thoát thứ hai.",
  "dn33:3.1.173": "Vị ấy chuyên chú chỉ vào cái đẹp.",
  "dn33:3.1.174": "Đây là giải thoát thứ ba.",
  "dn33:3.1.175": "Vượt hẳn mọi nhận biết về sắc, khi nhận biết về đối ngại đã lắng mất, không tác ý đến nhận biết sai khác, vị ấy chứng và an trú trong cảnh giới hư không vô biên, nghĩ rằng: ‘Hư không là vô biên.’",
  "dn33:3.1.176": "Đây là giải thoát thứ tư.",
  "dn33:3.1.177": "Vượt hẳn cảnh giới hư không vô biên, vị ấy chứng và an trú trong cảnh giới thức vô biên, nghĩ rằng: ‘Thức là vô biên.’",
  "dn33:3.1.178": "Đây là giải thoát thứ năm.",
  "dn33:3.1.179": "Vượt hẳn cảnh giới thức vô biên, vị ấy chứng và an trú trong cảnh giới không có gì cả, nghĩ rằng: ‘Không có gì cả.’",
  "dn33:3.1.180": "Đây là giải thoát thứ sáu.",
  "dn33:3.1.181": "Vượt hẳn cảnh giới không có gì cả, vị ấy chứng và an trú trong cảnh giới không phải có nhận biết cũng không phải không có nhận biết.",
  "dn33:3.1.182": "Đây là giải thoát thứ bảy.",
  "dn33:3.1.183": "Vượt hẳn cảnh giới không phải có nhận biết cũng không phải không có nhận biết, vị ấy chứng và an trú trong sự diệt của nhận biết và cảm thọ.",
  "dn33:3.1.184": "Đây là giải thoát thứ tám.",
  "dn33:3.1.185": "Này các hiền giả, đây là tám pháp đã được Thế Tôn, bậc biết, bậc thấy, bậc A-la-hán, bậc Chánh Đẳng Giác, khéo giảng dạy;",
  "dn33:3.1.186": "ở đây tất cả đều phải được cùng nhau tụng đọc … vì lợi ích, vì an vui cho chư thiên và loài người.",
  "dn33:3.2.0": "9. Chín pháp",
  "dn33:3.2.1": "Này các hiền giả, có chín pháp đã được Thế Tôn, bậc biết, bậc thấy, bậc A-la-hán, bậc Chánh Đẳng Giác, khéo giảng dạy;",
  "dn33:3.2.2": "ở đây tất cả đều phải được cùng nhau tụng đọc … vì lợi ích, vì an vui cho chư thiên và loài người.",
  "dn33:3.2.3": "Chín pháp là gì?",
  "dn33:3.2.4": "Chín điều làm khởi lên oán giận.",
  "dn33:3.2.5": "‘Người ấy đã làm hại tôi’, nên ôm oán giận;",
  "dn33:3.2.6": "‘Người ấy đang làm hại tôi’, nên ôm oán giận;",
  "dn33:3.2.7": "‘Người ấy sẽ làm hại tôi’, nên ôm oán giận;",
  "dn33:3.2.8": "‘Người ấy đã làm hại người tôi thương, người tôi quý’, nên ôm oán giận …",
  "dn33:3.2.9": "‘đang làm hại’, nên ôm oán giận …",
  "dn33:3.2.10": "‘sẽ làm hại’, nên ôm oán giận;",
  "dn33:3.2.11": "‘Người ấy đã làm lợi cho người tôi không ưa, người tôi không thích’, nên ôm oán giận …",
  "dn33:3.2.12": "‘đang làm lợi’, nên ôm oán giận …",
  "dn33:3.2.13": "‘sẽ làm lợi’, nên ôm oán giận.",
  "dn33:3.2.14": "Chín cách dẹp bỏ oán giận.",
  "dn33:3.2.15": "‘Người ấy đã làm hại tôi; nhưng ở đây có được gì đâu?’, nhờ vậy dẹp bỏ oán giận;",
  "dn33:3.2.16": "‘Người ấy đang làm hại tôi; nhưng ở đây có được gì đâu?’, nhờ vậy dẹp bỏ oán giận;",
  "dn33:3.2.17": "‘Người ấy sẽ làm hại tôi; nhưng ở đây có được gì đâu?’, nhờ vậy dẹp bỏ oán giận;",
  "dn33:3.2.18": "‘Người ấy đã làm hại người tôi thương, người tôi quý …",
  "dn33:3.2.19": "đang làm hại …",
  "dn33:3.2.20": "sẽ làm hại; nhưng ở đây có được gì đâu?’, nhờ vậy dẹp bỏ oán giận;",
  "dn33:3.2.21": "‘Người ấy đã làm lợi cho người tôi không ưa, người tôi không thích …",
  "dn33:3.2.22": "đang làm lợi …",
  "dn33:3.2.23": "người ấy sẽ làm hại ta, điều ấy ở đây làm sao có được’, vị ấy dẹp bỏ sự oán giận.",
  "dn33:3.2.24": "Chín chỗ ở của chúng sinh.",
  "dn33:3.2.25": "Này các hiền giả, có những chúng sinh thân khác nhau, tưởng khác nhau, như loài người, một số chư thiên và một số chúng sinh ở cõi đọa xứ.",
  "dn33:3.2.26": "Đây là chỗ ở thứ nhất của chúng sinh.",
  "dn33:3.2.27": "Này các hiền giả, có những chúng sinh thân khác nhau nhưng tưởng giống nhau, như chư thiên Phạm chúng mới sinh lần đầu.",
  "dn33:3.2.28": "Đây là chỗ ở thứ hai của chúng sinh.",
  "dn33:3.2.29": "Này các hiền giả, có những chúng sinh thân giống nhau nhưng tưởng khác nhau, như chư thiên Quang Âm.",
  "dn33:3.2.30": "Đây là chỗ ở thứ ba của chúng sinh.",
  "dn33:3.2.31": "Này các hiền giả, có những chúng sinh thân giống nhau, tưởng giống nhau, như chư thiên Biến Tịnh.",
  "dn33:3.2.32": "Đây là chỗ ở thứ tư của chúng sinh.",
  "dn33:3.2.33": "Này các hiền giả, có những chúng sinh không có tưởng, không có cảm nhận, như chư thiên Vô Tưởng.",
  "dn33:3.2.34": "Đây là chỗ ở thứ năm của chúng sinh.",
  "dn33:3.2.35": "Này các hiền giả, có những chúng sinh vượt hẳn mọi tưởng về sắc, do sự chấm dứt của tưởng về đối ngại, do không tác ý đến tưởng sai khác, nghĩ rằng: ‘hư không là vô biên’, nên đạt đến xứ hư không vô biên.",
  "dn33:3.2.36": "Đây là chỗ ở thứ sáu của chúng sinh.",
  "dn33:3.2.37": "Này các hiền giả, có những chúng sinh vượt hẳn xứ hư không vô biên, nghĩ rằng: ‘thức là vô biên’, nên đạt đến xứ thức vô biên.",
  "dn33:3.2.38": "Đây là chỗ ở thứ bảy của chúng sinh.",
  "dn33:3.2.39": "Này các hiền giả, có những chúng sinh vượt hẳn xứ thức vô biên, nghĩ rằng: ‘không có gì cả’, nên đạt đến xứ không có gì.",
  "dn33:3.2.40": "Đây là chỗ ở thứ tám của chúng sinh.",
  "dn33:3.2.41": "Này các hiền giả, có những chúng sinh vượt hẳn xứ không có gì, nên đạt đến xứ không phải tưởng cũng không phải không tưởng.",
  "dn33:3.2.42": "Đây là chỗ ở thứ chín của chúng sinh.",
  "dn33:3.2.43": "Chín lúc không thuận tiện, không đúng thời để sống đời phạm hạnh.",
  "dn33:3.2.44": "Này các hiền giả, ở đây, Như Lai xuất hiện ở đời, là bậc A-la-hán, bậc Chánh Đẳng Giác; pháp được giảng dạy là pháp đưa đến an tịnh, đưa đến tắt hẳn, đưa đến giác ngộ, do bậc Thiện Thệ tuyên thuyết.",
  "dn33:3.2.45": "Nhưng người này lại sinh vào địa ngục.",
  "dn33:3.2.46": "Đây là lúc không thuận tiện thứ nhất, không đúng thời để sống đời phạm hạnh.",
  "dn33:3.2.47": "Lại nữa, này các hiền giả, Như Lai xuất hiện ở đời, là bậc A-la-hán, bậc Chánh Đẳng Giác; pháp được giảng dạy là pháp đưa đến an tịnh, đưa đến tắt hẳn, đưa đến giác ngộ, do bậc Thiện Thệ tuyên thuyết.",
  "dn33:3.2.48": "Nhưng người này lại sinh vào loài súc sinh.",
  "dn33:3.2.49": "Đây là lúc không thuận tiện thứ hai, không đúng thời để sống đời phạm hạnh.",
  "dn33:3.2.50": "Lại nữa …",
  "dn33:3.2.51": "sinh vào cõi ngạ quỷ.",
  "dn33:3.2.52": "Đây là lúc không thuận tiện thứ ba, không đúng thời để sống đời phạm hạnh.",
  "dn33:3.2.53": "Lại nữa …",
  "dn33:3.2.54": "sinh vào chúng a-tu-la.",
  "dn33:3.2.55": "Đây là lúc không thuận tiện thứ tư, không đúng thời để sống đời phạm hạnh.",
  "dn33:3.2.56": "Lại nữa …",
  "dn33:3.2.57": "sinh vào một cõi trời sống lâu nào đó.",
  "dn33:3.2.58": "Đây là lúc không thuận tiện thứ năm, không đúng thời để sống đời phạm hạnh.",
  "dn33:3.2.59": "Lại nữa …",
  "dn33:3.2.60": "sinh ra ở các vùng biên địa, giữa những người man di, nơi không có đường đi đến với các tỳ-kheo, tỳ-kheo-ni, nam cư sĩ và nữ cư sĩ.",
  "dn33:3.2.61": "Đây là lúc không thuận tiện thứ sáu, không đúng thời để sống đời phạm hạnh.",
  "dn33:3.2.62": "Lại nữa …",
  "dn33:3.2.63": "sinh ra ở các xứ trung tâm. Nhưng người ấy có tà kiến, thấy biết điên đảo:",
  "dn33:3.2.64": "‘không có bố thí, không có cúng dường, không có tế lễ, không có quả và dị thục của các nghiệp lành dữ, không có đời này, không có đời sau, không có mẹ, không có cha, không có chúng sinh hóa sinh, không có ở đời những sa-môn, bà-la-môn sống đúng đường, hành đúng cách, tự mình biết rõ, chứng ngộ rồi tuyên bố đời này và đời sau’.",
  "dn33:3.2.65": "Đây là lúc không thuận tiện thứ bảy, không đúng thời để sống đời phạm hạnh.",
  "dn33:3.2.66": "Lại nữa …",
  "dn33:3.2.67": "sinh ra ở các xứ trung tâm. Nhưng người ấy ngu tối, đần độn, câm ngọng, không đủ khả năng hiểu nghĩa của lời nói hay và lời nói dở.",
  "dn33:3.2.68": "Đây là lúc không thuận tiện thứ tám, không đúng thời để sống đời phạm hạnh.",
  "dn33:3.2.69": "Lại nữa, này các hiền giả, Như Lai không xuất hiện ở đời, không có bậc A-la-hán, bậc Chánh Đẳng Giác,",
  "dn33:3.2.70": "pháp đưa đến an tịnh, đưa đến tắt hẳn, đưa đến giác ngộ, do bậc Thiện Thệ tuyên thuyết, cũng không được giảng dạy. Nhưng người này sinh ra ở các xứ trung tâm, lại có trí, không đần độn, không câm ngọng, đủ khả năng hiểu nghĩa của lời nói hay và lời nói dở.",
  "dn33:3.2.71": "Đây là lúc không thuận tiện thứ chín, không đúng thời để sống đời phạm hạnh.",
  "dn33:3.2.72": "Chín an trú tuần tự.",
  "dn33:3.2.73": "Này hiền giả, ở đây vị tỳ-kheo ly dục, lìa các pháp bất thiện, chứng và an trú thiền thứ nhất, có tầm có tứ, có hỷ lạc do ly dục sanh.",
  "dn33:3.2.74": "Do tầm và tứ lắng xuống … thiền thứ hai được chứng và an trú.",
  "dn33:3.2.75": "Do hỷ phai nhạt … thiền thứ ba được chứng và an trú.",
  "dn33:3.2.76": "Do xả bỏ lạc … thiền thứ tư được chứng và an trú.",
  "dn33:3.2.77": "Vượt hẳn mọi tưởng về sắc … chứng và an trú xứ không vô biên.",
  "dn33:3.2.78": "Vượt hẳn xứ không vô biên, nghĩ rằng: ‘thức là vô biên’, vị ấy chứng và an trú xứ thức vô biên.",
  "dn33:3.2.79": "Vượt hẳn xứ thức vô biên, nghĩ rằng: ‘không có gì cả’, vị ấy chứng và an trú xứ không có gì cả.",
  "dn33:3.2.80": "Vượt hẳn xứ không có gì cả, vị ấy chứng và an trú xứ không phải tưởng cũng không phải không tưởng.",
  "dn33:3.2.81": "Vượt hẳn xứ không phải tưởng cũng không phải không tưởng, vị ấy chứng và an trú diệt thọ tưởng.",
  "dn33:3.2.82": "Có chín sự diệt theo thứ lớp.",
  "dn33:3.2.83": "Với người đã nhập thiền thứ nhất, tưởng về dục được diệt.",
  "dn33:3.2.84": "Với người đã nhập thiền thứ hai, tầm và tứ được diệt.",
  "dn33:3.2.85": "Với người đã nhập thiền thứ ba, hỷ được diệt.",
  "dn33:3.2.86": "Với người đã nhập thiền thứ tư, hơi thở vào và hơi thở ra được diệt.",
  "dn33:3.2.87": "Với người đã nhập xứ không vô biên, tưởng về sắc được diệt.",
  "dn33:3.2.88": "Với người đã nhập xứ thức vô biên, tưởng về xứ không vô biên được diệt.",
  "dn33:3.2.89": "Với người đã nhập xứ không có gì cả, tưởng về xứ thức vô biên được diệt.",
  "dn33:3.2.90": "Với người đã nhập xứ không phải tưởng cũng không phải không tưởng, tưởng về xứ không có gì cả được diệt.",
  "dn33:3.2.91": "Với người đã nhập diệt thọ tưởng, tưởng và thọ được diệt.",
  "dn33:3.2.92": "Này hiền giả, đó là chín pháp đã được Thế Tôn, bậc biết, bậc thấy, bậc A-la-hán, bậc Chánh Đẳng Giác, khéo giảng dạy.",
  "dn33:3.2.93": "Ở đây tất cả đều phải cùng nhau kết tập … vì lợi ích, vì an vui cho chư thiên và loài người.",
  "dn33:3.3.0": "10. Mười pháp",
  "dn33:3.3.1": "Này hiền giả, có mười pháp đã được Thế Tôn, bậc biết, bậc thấy, bậc A-la-hán, bậc Chánh Đẳng Giác, khéo giảng dạy.",
  "dn33:3.3.2": "Ở đây tất cả đều phải cùng nhau kết tập … vì lợi ích, vì an vui cho chư thiên và loài người.",
  "dn33:3.3.3": "Mười pháp ấy là gì?",
  "dn33:3.3.4": "Mười pháp làm chỗ nương tựa.",
  "dn33:3.3.5": "Này hiền giả, ở đây vị tỳ-kheo có giới, sống phòng hộ với sự phòng hộ của giới bổn, đầy đủ nết hạnh và chỗ lui tới, thấy sợ trong những lỗi nhỏ nhặt, thọ trì và học tập trong các điều học.",
  "dn33:3.3.6": "Này hiền giả, việc vị tỳ-kheo có giới, sống phòng hộ với sự phòng hộ của giới bổn, đầy đủ nết hạnh và chỗ lui tới, thấy sợ trong những lỗi nhỏ nhặt, thọ trì và học tập trong các điều học,",
  "dn33:3.3.7": "đó cũng là một pháp làm chỗ nương tựa.",
  "dn33:3.3.8": "Lại nữa, này hiền giả, vị tỳ-kheo nghe nhiều, giữ gìn điều đã nghe, tích lũy điều đã nghe. Những pháp nào tốt đẹp ở đầu, tốt đẹp ở giữa, tốt đẹp ở cuối, có nghĩa có lời đầy đủ, chỉ bày đời sống phạm hạnh hoàn toàn đầy đủ và trong sạch, những pháp như vậy vị ấy được nghe nhiều, ghi nhớ, quen thuộc bằng lời nói, suy xét bằng tâm, thấu rõ bằng chánh kiến.",
  "dn33:3.3.9": "Này hiền giả, việc vị tỳ-kheo nghe nhiều … thấu rõ bằng chánh kiến,",
  "dn33:3.3.10": "đó cũng là một pháp làm chỗ nương tựa.",
  "dn33:3.3.11": "Lại nữa, này hiền giả, vị tỳ-kheo có bạn lành, có bạn đồng hành lành, có người cùng sống lành.",
  "dn33:3.3.12": "Này hiền giả, việc vị tỳ-kheo có bạn lành, có bạn đồng hành lành, có người cùng sống lành,",
  "dn33:3.3.13": "đó cũng là một pháp làm chỗ nương tựa.",
  "dn33:3.3.14": "Lại nữa, này hiền giả, vị tỳ-kheo dễ dạy, có đủ những pháp khiến dễ dạy, kham nhẫn, biết đón nhận lời chỉ dạy một cách đúng đắn.",
  "dn33:3.3.15": "Này hiền giả, việc vị tỳ-kheo dễ dạy … biết đón nhận lời chỉ dạy một cách đúng đắn,",
  "dn33:3.3.16": "đó cũng là một pháp làm chỗ nương tựa.",
  "dn33:3.3.17": "Lại nữa, này hiền giả, đối với những việc lớn nhỏ cần làm cho các bạn đồng phạm hạnh, vị tỳ-kheo ấy khéo léo, không lười biếng, có suy xét về phương cách trong việc ấy, có khả năng làm và có khả năng sắp đặt.",
  "dn33:3.3.18": "Này hiền giả, việc vị tỳ-kheo đối với những việc cần làm cho các bạn đồng phạm hạnh … có khả năng sắp đặt,",
  "dn33:3.3.19": "đó cũng là một pháp làm chỗ nương tựa.",
  "dn33:3.3.20": "Lại nữa, này hiền giả, vị tỳ-kheo yêu thích pháp, ưa nói về pháp, rất hoan hỷ đối với pháp và luật.",
  "dn33:3.3.21": "Này hiền giả, việc vị tỳ-kheo yêu thích pháp … rất hoan hỷ đối với pháp và luật,",
  "dn33:3.3.22": "đó cũng là một pháp làm chỗ nương tựa.",
  "dn33:3.3.23": "Lại nữa, này hiền giả, vị tỳ-kheo biết đủ với bất cứ loại y áo, đồ ăn khất thực, chỗ ở, và thuốc men vật dụng trị bệnh nào.",
  "dn33:3.3.24": "Này hiền giả, việc vị tỳ-kheo biết đủ … với các vật dụng ấy,",
  "dn33:3.3.25": "đó cũng là một pháp làm chỗ nương tựa.",
  "dn33:3.3.26": "Lại nữa, này hiền giả, vị tỳ-kheo sống tinh cần, để đoạn trừ các pháp bất thiện, để thành tựu các pháp thiện, có sức mạnh, nỗ lực vững chắc, không bỏ gánh nặng đối với các pháp thiện.",
  "dn33:3.3.27": "Này hiền giả, việc vị tỳ-kheo sống tinh cần … không bỏ gánh nặng đối với các pháp thiện,",
  "dn33:3.3.28": "đó cũng là một pháp làm chỗ nương tựa.",
  "dn33:3.3.29": "Lại nữa, này các hiền giả, vị tỳ-kheo là người có chánh niệm, đầy đủ sự khéo léo tột bậc về niệm, nhớ lại và ghi nhớ được cả những việc đã làm từ lâu, những lời đã nói từ lâu.",
  "dn33:3.3.30": "Này các hiền giả, vị tỳ-kheo là người có chánh niệm … nhớ lại và ghi nhớ được.",
  "dn33:3.3.31": "Pháp này cũng là pháp làm chỗ nương tựa.",
  "dn33:3.3.32": "Lại nữa, này các hiền giả, vị tỳ-kheo là người có trí tuệ, đầy đủ trí tuệ thấy sự sinh diệt, là trí tuệ bậc thánh, thấu suốt, đưa đến chấm dứt khổ một cách chân chánh.",
  "dn33:3.3.33": "Này các hiền giả, vị tỳ-kheo là người có trí tuệ … đưa đến chấm dứt khổ một cách chân chánh.",
  "dn33:3.3.34": "Pháp này cũng là pháp làm chỗ nương tựa.",
  "dn33:3.3.35": "Mười đề mục toàn thể.",
  "dn33:3.3.36": "Có người nhận biết đề mục toàn thể về đất, ở trên, ở dưới, ngang khắp, không hai, vô lượng.",
  "dn33:3.3.37": "Có người nhận biết đề mục toàn thể về nước …",
  "dn33:3.3.38": "Có người nhận biết đề mục toàn thể về lửa …",
  "dn33:3.3.39": "Có người nhận biết đề mục toàn thể về gió …",
  "dn33:3.3.40": "Có người nhận biết đề mục toàn thể về màu xanh …",
  "dn33:3.3.41": "Có người nhận biết đề mục toàn thể về màu vàng …",
  "dn33:3.3.42": "Có người nhận biết đề mục toàn thể về màu đỏ …",
  "dn33:3.3.43": "Có người nhận biết đề mục toàn thể về màu trắng …",
  "dn33:3.3.44": "Có người nhận biết đề mục toàn thể về hư không …",
  "dn33:3.3.45": "Có người nhận biết đề mục toàn thể về thức, ở trên, ở dưới, ngang khắp, không hai, vô lượng.",
  "dn33:3.3.46": "Mười đường nghiệp bất thiện —",
  "dn33:3.3.47": "sát sinh, lấy của không cho, tà hạnh trong dục, nói dối, nói hai lưỡi, nói lời thô ác, nói chuyện vô ích, tham lam, ác ý, tà kiến.",
  "dn33:3.3.48": "Mười đường nghiệp thiện —",
  "dn33:3.3.49": "tránh sát sinh, tránh lấy của không cho, tránh tà hạnh trong dục, tránh nói dối, tránh nói hai lưỡi, tránh nói lời thô ác, tránh nói chuyện vô ích, không tham lam, không ác ý, chánh kiến.",
  "dn33:3.3.50": "Mười chỗ ở của bậc thánh.",
  "dn33:3.3.51": "Ở đây, này các hiền giả, vị tỳ-kheo đã từ bỏ năm phần, đầy đủ sáu phần, có một sự phòng hộ, có bốn chỗ nương, đã dứt bỏ những chân lý riêng lẻ, đã làm lắng yên sự tìm cầu, ý nghĩ không vẩn đục, thân hành đã lắng dịu, tâm khéo giải thoát, tuệ khéo giải thoát.",
  "dn33:3.3.52": "Và này các hiền giả, thế nào là vị tỳ-kheo đã từ bỏ năm phần?",
  "dn33:3.3.53": "Ở đây, này các hiền giả, nơi vị tỳ-kheo, dục tham đã được từ bỏ, ác ý đã được từ bỏ, hôn trầm thụy miên đã được từ bỏ, trạo cử hối quá đã được từ bỏ, nghi đã được từ bỏ.",
  "dn33:3.3.54": "Như vậy, này các hiền giả, vị tỳ-kheo là người đã từ bỏ năm phần.",
  "dn33:3.3.55": "Và này các hiền giả, thế nào là vị tỳ-kheo đầy đủ sáu phần?",
  "dn33:3.3.56": "Ở đây, này các hiền giả, vị tỳ-kheo khi mắt thấy sắc thì không vui mừng cũng không buồn bực, sống với tâm xả, có chánh niệm, tỉnh giác.",
  "dn33:3.3.57": "Khi tai nghe tiếng …",
  "dn33:3.3.58": "Khi ý nhận biết pháp thì không vui mừng cũng không buồn bực, sống với tâm xả, có chánh niệm, tỉnh giác.",
  "dn33:3.3.59": "Như vậy, này các hiền giả, vị tỳ-kheo là người đầy đủ sáu phần.",
  "dn33:3.3.60": "Và này các hiền giả, thế nào là vị tỳ-kheo có một sự phòng hộ?",
  "dn33:3.3.61": "Ở đây, này các hiền giả, vị tỳ-kheo đầy đủ tâm được phòng hộ bởi niệm.",
  "dn33:3.3.62": "Như vậy, này các hiền giả, vị tỳ-kheo là người có một sự phòng hộ.",
  "dn33:3.3.63": "Và này các hiền giả, thế nào là vị tỳ-kheo có bốn chỗ nương?",
  "dn33:3.3.64": "Ở đây, này các hiền giả, vị tỳ-kheo có suy xét rồi mới thọ dụng một thứ, có suy xét rồi mới chịu đựng một thứ, có suy xét rồi mới tránh né một thứ, có suy xét rồi mới trừ bỏ một thứ.",
  "dn33:3.3.65": "Như vậy, này các hiền giả, vị tỳ-kheo là người có bốn chỗ nương.",
  "dn33:3.3.66": "Và này các hiền giả, thế nào là vị tỳ-kheo đã dứt bỏ những chân lý riêng lẻ?",
  "dn33:3.3.67": "Ở đây, này các hiền giả, những chân lý riêng lẻ đủ loại của các sa-môn, bà-la-môn phàm tục đều đã bị vị tỳ-kheo ấy xua bỏ, dứt bỏ, nhổ bỏ, mửa bỏ, buông bỏ, từ bỏ, xả bỏ.",
  "dn33:3.3.68": "Như vậy, này các hiền giả, vị tỳ-kheo là người đã dứt bỏ những chân lý riêng lẻ.",
  "dn33:3.3.69": "Và này các hiền giả, thế nào là vị tỳ-kheo đã làm lắng yên sự tìm cầu?",
  "dn33:3.3.70": "Ở đây, này các hiền giả, nơi vị tỳ-kheo, sự tìm cầu dục đã được từ bỏ, sự tìm cầu hiện hữu đã được từ bỏ, sự tìm cầu đời sống phạm hạnh đã lắng yên.",
  "dn33:3.3.71": "Như vậy, này các hiền giả, vị tỳ-kheo là người đã làm lắng yên sự tìm cầu.",
  "dn33:3.3.72": "Và này các hiền giả, thế nào là vị tỳ-kheo có ý nghĩ không vẩn đục?",
  "dn33:3.3.73": "Ở đây, này các hiền giả, nơi vị tỳ-kheo, ý nghĩ về dục đã được từ bỏ, ý nghĩ về ác ý đã được từ bỏ, ý nghĩ về hại người đã được từ bỏ.",
  "dn33:3.3.74": "Như vậy, này các hiền giả, vị tỳ-kheo là người có ý nghĩ không vẩn đục.",
  "dn33:3.3.75": "Và này các hiền giả, thế nào là vị tỳ-kheo có thân hành đã lắng dịu?",
  "dn33:3.3.76": "Ở đây, này các hiền giả, vị tỳ-kheo do từ bỏ lạc, từ bỏ khổ, do trước đó hỷ và ưu đã chấm dứt, chứng và an trú thiền thứ tư, không khổ không lạc, thanh tịnh nhờ xả niệm.",
  "dn33:3.3.77": "Như vậy, này các hiền giả, vị tỳ-kheo là người có thân hành đã lắng dịu.",
  "dn33:3.3.78": "Và này các hiền giả, thế nào là vị tỳ-kheo có tâm khéo giải thoát?",
  "dn33:3.3.79": "Này hiền giả, ở đây tâm vị tỳ-kheo được giải thoát khỏi tham, được giải thoát khỏi sân, được giải thoát khỏi si.",
  "dn33:3.3.80": "Như vậy, này hiền giả, vị tỳ-kheo là người có tâm khéo giải thoát.",
  "dn33:3.3.81": "Và này hiền giả, thế nào là vị tỳ-kheo có trí khéo giải thoát?",
  "dn33:3.3.82": "Này hiền giả, ở đây vị tỳ-kheo biết rõ: ‘Tham của ta đã được đoạn trừ, bị chặt tận gốc, như gốc cây thốt nốt bị nhổ lên, không còn hiện hữu, về sau không còn sinh khởi nữa.’",
  "dn33:3.3.83": "Biết rõ: ‘Sân của ta đã được đoạn trừ, bị chặt tận gốc, như gốc cây thốt nốt bị nhổ lên, không còn hiện hữu, về sau không còn sinh khởi nữa.’",
  "dn33:3.3.84": "Biết rõ: ‘Si của ta đã được đoạn trừ, bị chặt tận gốc, như gốc cây thốt nốt bị nhổ lên, không còn hiện hữu, về sau không còn sinh khởi nữa.’",
  "dn33:3.3.85": "Như vậy, này hiền giả, vị tỳ-kheo là người có trí khéo giải thoát.",
  "dn33:3.3.86": "Mười pháp vô học là:",
  "dn33:3.3.87": "chánh kiến vô học, chánh tư duy vô học, chánh ngữ vô học, chánh nghiệp vô học, chánh mạng vô học, chánh tinh tấn vô học, chánh niệm vô học, chánh định vô học, chánh trí vô học, chánh giải thoát vô học.",
  "dn33:3.3.88": "Này hiền giả, đây là mười pháp đã được Thế Tôn, bậc biết, bậc thấy, bậc A-la-hán, bậc Chánh Đẳng Giác, khéo giảng dạy.",
  "dn33:3.3.89": "Ở đây tất cả đều phải cùng nhau tụng đọc, không nên tranh cãi, để đời sống phạm hạnh này được bền lâu, tồn tại dài lâu, vì lợi ích cho nhiều người, vì hạnh phúc cho nhiều người, vì lòng thương đời, vì lợi ích, vì an vui cho chư thiên và loài người.”",
  "dn33:3.4.1": "Rồi Thế Tôn đứng dậy và nói với tôn giả Xá-lợi-phất:",
  "dn33:3.4.2": "“Lành thay, lành thay, Xá-lợi-phất,",
  "dn33:3.4.3": "thật khéo thay, Xá-lợi-phất, ông đã nói pháp môn trùng tụng cho các tỳ-kheo.”",
  "dn33:3.4.4": "Tôn giả Xá-lợi-phất nói như vậy, và bậc Đạo Sư đã chấp thuận.",
  "dn33:3.4.5": "Các vị tỳ-kheo hoan hỷ, vui mừng trước lời dạy của tôn giả Xá-lợi-phất.",
  "dn33:3.4.6": "Kinh Trùng Tụng, bài thứ mười, chấm dứt."
}
window.BILARA["dn33"]["vi"]["dn33:source"] =
  "Dịch từ nguồn Pali https://suttacentral.net/";
